globalThis.__BQ = {"anafazMitoz":{"ilkokul":{"kolay":[{"q":"Mitozun anafaz evresinde kardeş kromatitler birbirinden ayrılarak nereye doğru gider?","steps":[{"t":"Kromatitler ayrılıyor","a":"Eşleşmiş iki kromatit ayrılır","d":"Anafazda her kromozomu oluşturan iki kardeş kromatit birbirinden ayrılır. Ayrılan parçalar artık ayrı birer kromozom gibi davranır."},{"t":"Kutuplara hareket","a":"Zıt yönlere çekilir","d":"Ayrılan kardeş kromatitler hücrenin birbirine zıt iki ucuna, yani kutuplara doğru çekilir. Böylece hücrenin iki ucunda da kromozomlar toplanır."}],"ans":"Hücrenin zıt iki kutbuna (ucuna) doğru gider."},{"q":"Anafazda kardeş kromatitleri kutuplara çeken yapı nedir?","steps":[{"t":"İğ ipliklerini bulma","a":"İnce iplikler kromozomlara bağlıdır","d":"Hücrede iğ iplikleri denilen ince iplikler bulunur. Bu iplikler kromozomlara tutunmuştur."},{"t":"Çekme işlemi","a":"İplikler kısalır","d":"İğ iplikleri anafazda kısalarak kromatitleri kutuplara doğru çeker. Bu sayede kromatitler yer değiştirir."}],"ans":"İğ iplikleri çeker."},{"q":"Anafaz sırasında kromatitlerin birleştiği nokta olan sentromere ne olur?","steps":[{"t":"Sentromeri tanıma","a":"Kromatitlerin bağlı olduğu nokta","d":"Sentromer, iki kardeş kromatiti bir arada tutan ortak noktadır. Anafaza kadar kromatitler buradan birbirine bağlıdır."},{"t":"Ayrılma anı","a":"Sentromer bölünür","d":"Anafazın başında sentromer bölünür ve kardeş kromatitler serbest kalır. Böylece kromatitler ayrı ayrı hareket edebilir."}],"ans":"Sentromer bölünür ve kardeş kromatitler ayrılır."},{"q":"Mitozda anafaz bittiğinde hücrenin her iki kutbunda da kromozom sayısı nasıldır?","steps":[{"t":"Eşit dağılım","a":"Her kutba eşit sayı gider","d":"Anafazda kromatitler iki kutba eşit olarak dağılır. Bir kutba giden kromozom sayısı, diğer kutba gidenle aynıdır."},{"t":"Sonuç","a":"İki kutup özdeş","d":"İşlem bittiğinde her iki kutupta da aynı sayıda kromozom bulunur. Böylece dengeli bir dağılım sağlanır."}],"ans":"Her iki kutupta da kromozom sayısı eşittir."},{"q":"Anafaz, mitozun kaçıncı evresidir ve hangi evreden hemen sonra gelir?","steps":[{"t":"Evre sırası","a":"Profaz, metafaz, anafaz","d":"Mitoz; profaz, metafaz, anafaz ve telofaz olarak sıralanır. Anafaz bu sıralamada üçüncü evredir."},{"t":"Önceki evre","a":"Metafazdan sonra","d":"Anafaz, kromozomların orta hatta dizildiği metafazdan hemen sonra gelir. Metafaz bittiğinde anafaz başlar."}],"ans":"Üçüncü evredir; metafazdan hemen sonra gelir."}],"zor":[{"q":"Bir hücrede 8 kromozom varken anafazda kromatitler ayrılınca hücrenin her kutbuna kaç kromozom gider?","steps":[{"t":"Başlangıç sayısı","a":"8 kromozom var","d":"Hücre anafaza girdiğinde toplam 8 kromozom bulunur. Bu kromozomların her biri iki kromatitten oluşur."},{"t":"Kromatit ayrılması","a":"Her kromozom ikiye ayrılır","d":"Anafazda her kromozomdaki iki kardeş kromatit ayrılır. Ayrılan kromatitler artık ayrı kromozom sayılır."},{"t":"Kutuplara dağılım","a":"Eşit paylaşım","d":"Ayrılan kromozomlar iki kutba eşit dağılır. Her kutba ana hücredeki kadar, yani 8 kromozom gider."}],"ans":"Her kutba 8 kromozom gider."},{"q":"Anafazda kardeş kromatitler ayrılmadan önce ve ayrıldıktan sonra hücredeki kromozom yapısı nasıl değişir?","steps":[{"t":"Ayrılmadan önce","a":"Çift kromatitli","d":"Anafazdan önce her kromozom iki kardeş kromatit halindedir. Kromatitler sentromerden birbirine bağlıdır."},{"t":"Ayrıldıktan sonra","a":"Tek kromatitli","d":"Anafazda sentromer bölününce her kromatit ayrı bir kromozom olur. Kutuplara giden kromozomlar tek kromatitlidir."}],"ans":"Çift kromatitli kromozomlar tek kromatitli kromozomlara dönüşür."},{"q":"Anafazda iğ iplikleri kısalmasaydı kromatitlerin dağılımı nasıl etkilenirdi?","steps":[{"t":"İpliklerin görevi","a":"İplikler kromatitleri çeker","d":"İğ iplikleri kısalarak kromatitleri kutuplara taşır. Kısalma olmazsa çekme işlemi gerçekleşmez."},{"t":"Olası sonuç","a":"Dağılım bozulur","d":"İplikler kısalmazsa kromatitler kutuplara çekilemez. Bu durumda kromozomlar eşit dağılamaz ve hücreler hatalı oluşur."}],"ans":"Kromatitler kutuplara çekilemez ve eşit dağılamaz."},{"q":"Anafaz evresi mitozun en kısa evresi sayılır; bu evrede temel olarak hangi olay gerçekleşir?","steps":[{"t":"Evrenin özelliği","a":"Hızlı gerçekleşir","d":"Anafaz, mitozun süresi en kısa evresidir. Çok hızlı bir şekilde tamamlanır."},{"t":"Temel olay","a":"Kromatitler ayrılır","d":"Bu evrede kardeş kromatitler ayrılıp zıt kutuplara çekilir. Bu temel olay anafazı diğer evrelerden ayırır."}],"ans":"Kardeş kromatitlerin ayrılıp zıt kutuplara çekilmesi."},{"q":"Anafazda kromozomların harf \"V\" şeklinde görünmesinin nedeni nedir?","steps":[{"t":"Çekilme noktası","a":"Sentromerden çekilir","d":"İğ iplikleri kromozomu sentromer noktasından çeker. Çekme önce ortadan başlar."},{"t":"Görünüm","a":"Kollar geride kalır","d":"Sentromer öne giderken kromozomun kolları geride kalır. Bu da kromozoma V benzeri bir görünüm kazandırır."}],"ans":"Sentromer öne, kollar geriye kaldığı için V şekli oluşur."}]},"ortaokul":{"kolay":[{"q":"Mitoz anafazda kardeş kromatitlerin ayrılması için sentromerde gerçekleşen olay nedir?","steps":[{"t":"Sentromerin yapısı","a":"Kromatitleri tutar","d":"Sentromer, iki kardeş kromatiti birbirine bağlayan ortak bölgedir. Anafaza kadar bu bağlantı korunur."},{"t":"Bölünme","a":"Sentromer ayrılır","d":"Anafazda sentromer ikiye ayrılır ve kromatitler serbest kalır. Bu, kromatitlerin kutuplara gidebilmesini sağlar."}],"ans":"Sentromer bölünerek kardeş kromatitler ayrılır."},{"q":"Anafazda iğ ipliklerinin kısalması kromozom hareketini nasıl sağlar?","steps":[{"t":"İplik bağlantısı","a":"İplikler kromozoma tutunur","d":"İğ iplikleri kromozomların sentromer bölgesine tutunur. Her iplik bir kutuptan uzanır."},{"t":"Kısalma etkisi","a":"Kromatitler kutuplara çekilir","d":"İplikler kısaldıkça tutundukları kromatitleri kendi kutuplarına doğru çeker. Böylece kromatitler hücrenin uçlarına taşınır."}],"ans":"İplikler kısaldıkça kromatitleri kutuplara çeker."},{"q":"Anafaz sonunda hücrenin her kutbuna giden kromozom takımının ana hücreyle ilişkisi nedir?","steps":[{"t":"Kromozom dağılımı","a":"Eşit gider","d":"Anafazda kromatitler iki kutba eşit olarak dağılır. Her kutba ana hücreyle aynı sayıda kromozom gider."},{"t":"Sonuç","a":"Aynı takım oluşur","d":"Böylece her kutupta ana hücredeki kromozom takımının aynısı bulunur. Bu, mitozun özdeş hücre üretme amacına uygundur."}],"ans":"Her kutba ana hücreyle aynı kromozom takımı gider."},{"q":"Anafaz evresi metafaz ile telofaz arasında yer alır; bu evrede kromozomların konumu nasıl değişir?","steps":[{"t":"Metafaz konumu","a":"Ortada dizili","d":"Metafazda kromozomlar hücrenin tam ortasında bir hat üzerinde dizilir. Bu hatta ekvatoral düzlem denir."},{"t":"Anafaz hareketi","a":"Kutuplara dağılır","d":"Anafazda kromatitler ortadan ayrılıp zıt kutuplara çekilir. Böylece kromozomlar ortadan uçlara doğru taşınır."}],"ans":"Ortadaki dizilimden zıt kutuplara dağılırlar."},{"q":"Mitoz anafazda her kutba özdeş kromozom takımı gitmesi hücreler için neden önemlidir?","steps":[{"t":"Özdeşlik gerekliliği","a":"Aynı kalıtsal bilgi","d":"Her kutba özdeş kromozom takımı gitmesi, oluşacak hücrelerin aynı kalıtsal bilgiye sahip olmasını sağlar. Böylece hücreler birbirinin aynısı olur."},{"t":"Önem","a":"Doğru kalıtım","d":"Bu özdeşlik, vücudun büyümesinde ve onarımında doğru bilgi aktarımını garanti eder. Hatalı dağılım canlıya zarar verebilir."}],"ans":"Oluşan hücrelerin ana hücreyle aynı kalıtsal bilgiye sahip olmasını sağlar."}],"zor":[{"q":"2n=12 kromozomlu bir hücrede anafaz sırasında zıt kutuplara doğru hareket eden toplam kromozom (kromatit) sayısı kaçtır?","steps":[{"t":"Başlangıç","a":"12 çift kromatitli kromozom","d":"Hücrede 2n=12, yani 12 kromozom vardır. Anafaz başında her kromozom iki kardeş kromatitten oluşur."},{"t":"Ayrılma","a":"24 kromatit oluşur","d":"Sentromerler bölününce 12 kromozomun her biri ikiye ayrılır. Böylece toplam 24 kromatit serbest kalır."},{"t":"Hareket","a":"Tümü kutuplara gider","d":"Bu 24 kromatit aynı anda zıt kutuplara çekilir. Her kutba 12 kromatit (kromozom) gider."}],"ans":"Toplam 24 kromatit hareket eder; her kutba 12 gider."},{"q":"Anafazda kohezin adı verilen tutucu proteinlerin parçalanması neden gereklidir?","steps":[{"t":"Kohezinin görevi","a":"Kromatitleri bağlar","d":"Kohezin proteinleri kardeş kromatitleri sentromer çevresinde bir arada tutar. Bu bağ anafaza kadar korunur."},{"t":"Parçalanma","a":"Kromatitler serbest kalır","d":"Anafazda kohezin proteinleri parçalanır ve kromatitler arasındaki bağ kopar. Bu olmadan iğ iplikleri kromatitleri ayıramaz."},{"t":"Sonuç","a":"Ayrılma gerçekleşir","d":"Kohezin parçalandıktan sonra iğ iplikleri kromatitleri zıt kutuplara çeker. Böylece eşit dağılım sağlanır."}],"ans":"Kardeş kromatitlerin serbest kalıp kutuplara ayrılabilmesi için gereklidir."},{"q":"Anafazda iğ ipliklerinin bir kısmı kutuplar arasında uzayarak hücrenin uzamasına neden olur; bu durum sonraki evreyi nasıl etkiler?","steps":[{"t":"İki tür iplik","a":"Çekici ve itici iplikler","d":"İğ ipliklerinin bir kısmı kromatitleri çekerken bir kısmı kutuplar arasında uzar. Bu uzayan iplikler hücreyi boylamasına genişletir."},{"t":"Hücre uzaması","a":"Kutuplar uzaklaşır","d":"İplikler uzadıkça iki kutup birbirinden daha da uzaklaşır. Hücre giderek uzar."},{"t":"Sonraki evre etkisi","a":"Bölünmeye hazırlık","d":"Bu uzama, sitoplazmanın ileride ortadan ikiye bölünmesini kolaylaştırır. Telofaz ve sitokineze zemin hazırlar."}],"ans":"Hücreyi uzatarak sitoplazmanın bölünmesine zemin hazırlar."},{"q":"Anafazda kromatitlerden biri yanlışlıkla aynı kutba giderse oluşacak hücrelerde nasıl bir sorun ortaya çıkar?","steps":[{"t":"Normal durum","a":"Eşit dağılım beklenir","d":"Normalde her kromozomun kromatitleri farklı kutuplara gider. Böylece iki kutup eşit ve özdeş kromozom alır."},{"t":"Hatalı dağılım","a":"Bir kutup fazla alır","d":"İki kromatit aynı kutba giderse o kutup bir fazla kromozom alır. Diğer kutup ise bir eksik kalır."},{"t":"Sonuç","a":"Sayı bozukluğu","d":"Oluşan hücrelerden biri fazla, diğeri eksik kromozomlu olur. Bu kromozom sayısı bozukluğu hücrenin sağlığını etkiler."}],"ans":"Bir hücre fazla, diğeri eksik kromozomlu olur (sayı bozukluğu)."},{"q":"Anafazda kromatitlerin sentromer bölgesinden çekilmesi kromozomlara neden bükülmüş (V veya J) bir görünüm verir?","steps":[{"t":"Çekme noktası","a":"Sentromer öne gider","d":"İğ iplikleri kromozomu yalnızca sentromer bölgesinden çeker. Bu nedenle önce sentromer kutba doğru ilerler."},{"t":"Kolların durumu","a":"Geride sürüklenir","d":"Sentromer öne giderken kromozomun kolları henüz çekilmediği için geride sürüklenir. Bu, kola bükülmüş bir hat verir."},{"t":"Şekil","a":"Sentromer konumuna göre değişir","d":"Sentromer ortadaysa kromozom V, kenardaysa J görünümü alır. Bu görünüm anafazın tipik özelliğidir."}],"ans":"Sentromer öne çekilip kollar geride kaldığı için V ya da J görünümü oluşur."}]},"lise":{"kolay":[{"q":"Mitoz anafazda kardeş kromatitlerin ayrılmasını tetikleyen temel olay nedir?","steps":[{"t":"Sentromerin durumu","a":"Kromatitler sentromerden bağlı","d":"Anafaza kadar kardeş kromatitler sentromer bölgesindeki proteinlerle bir arada tutulur. Bu bağlantı dağılımdan önce korunur."},{"t":"Tetikleyici olay","a":"Sentromer ayrımı","d":"Anafazın başında sentromer bölgesindeki tutucu yapılar çözülür. Bu sayede kardeş kromatitler birbirinden tamamen ayrılır."},{"t":"Sonuç","a":"Bağımsız kromozomlar","d":"Ayrılan her kromatit artık bağımsız bir kromozom olarak hareket eder. Bu kromozomlar iğ iplikleriyle kutuplara taşınır."}],"ans":"Sentromerlerin bölünmesiyle kardeş kromatitlerin ayrılması."},{"q":"Anafazda iğ ipliklerinin kısalmasının kromozom hareketindeki rolü nedir?","steps":[{"t":"İplik tutunması","a":"Kinetokora bağlanır","d":"İğ iplikleri kromozomların sentromer çevresindeki kinetokor bölgesine tutunur. Her kromatit bir kutuptan gelen iplikle bağlıdır."},{"t":"Kısalma","a":"Kromatitler çekilir","d":"İplikler kinetokor ucundan kısalarak kromatitleri kendi kutuplarına çeker. Bu kısalma kromozom hareketinin itici gücüdür."},{"t":"Yön","a":"Zıt kutuplara","d":"Bir kromozomun iki kromatiti zıt kutuplara doğru çekilir. Böylece kromozom takımları iki kutba ayrılır."}],"ans":"İplikler kısalarak kromatitleri zıt kutuplara çeker."},{"q":"Anafaz sonunda her kutuptaki kromozom sayısının ana hücreyle aynı kalmasının nedeni nedir?","steps":[{"t":"Önceki kopyalama","a":"DNA önceden eşlendi","d":"İnterfazda her kromozom kendini kopyalayarak iki kardeş kromatit oluşturmuştu. Yani genetik madde anafazdan önce iki katına çıkmıştı."},{"t":"Eşit dağılım","a":"Kromatitler paylaşılır","d":"Anafazda her kromozomun bir kromatiti bir kutba, diğeri öteki kutba gider. Böylece kopyalar iki kutba bölünür."},{"t":"Sayı korunması","a":"Aynı sayı","d":"Her kutup, ana hücredekiyle aynı sayıda kromozom alır. Bu yüzden kromozom sayısı değişmeden korunur."}],"ans":"Kromatitler eşit dağıldığı için her kutup ana hücreyle aynı sayıyı alır."},{"q":"Anafaz A ve anafaz B olarak adlandırılan iki alt süreç nedir?","steps":[{"t":"Anafaz A","a":"Kromatitler kutba çekilir","d":"Anafaz A sürecinde kinetokor iplikleri kısalarak kromatitleri kutuplara doğru çeker. Bu, kromozomların kutuplara yaklaşmasını sağlar."},{"t":"Anafaz B","a":"Kutuplar uzaklaşır","d":"Anafaz B sürecinde kutuplar arası iplikler uzar ve iki kutbu birbirinden uzaklaştırır. Böylece hücre boyca uzar."},{"t":"Birlikte","a":"Tam ayrılma","d":"İki süreç birlikte kromozom takımlarının iyice ayrılmasını sağlar. Bu, telofaz öncesi hazırlığı tamamlar."}],"ans":"Anafaz A kromatitleri kutba çeker; anafaz B kutupları uzaklaştırır."},{"q":"Anafazda kromatitlerin sentromerden çekilmesi neden kromozomlara V veya J görünümü kazandırır?","steps":[{"t":"Çekme noktası","a":"Yalnız sentromer çekilir","d":"İğ iplikleri kromozomu yalnızca sentromer bölgesinden tutar ve çeker. Bu nedenle sentromer kutba doğru öne çıkar."},{"t":"Kolların gerilemesi","a":"Sürüklenir","d":"Kromozom kolları doğrudan çekilmediğinden sentromerin gerisinde sürüklenir. Bu, kola bükülme görünümü verir."},{"t":"Şekil","a":"Sentromer konumu","d":"Sentromer ortadaysa V, uca yakınsa J şekli oluşur. Bu görünüm anafazın ayırt edici özelliğidir."}],"ans":"Sentromer öne, kollar geride çekildiği için V ya da J görünümü oluşur."},{"q":"Anafazda kromozomların hareket etmesini sağlayan iğ ipliklerinin yapı taşı nedir?","steps":[{"t":"İplik yapısı","a":"Mikrotübül","d":"İğ iplikleri mikrotübül adı verilen protein borucuklarından oluşur. Bu yapılar hücre iskeletinin bir parçasıdır."},{"t":"Mikrotübül davranışı","a":"Uzar ve kısalır","d":"Mikrotübüller uçlarından protein ekleyip çıkararak uzayabilir veya kısalabilir. Bu özellik kromozom hareketini sağlar."},{"t":"İşlev","a":"Çekme kuvveti","d":"Kısalan mikrotübüller kromatitleri kutuplara doğru çeker. Böylece kromozomlar yer değiştirir."}],"ans":"Mikrotübül adı verilen protein iplikleridir."},{"q":"Anafazda kromatitlerin eşit dağılması mitozun hangi temel amacına hizmet eder?","steps":[{"t":"Mitozun amacı","a":"Özdeş hücre üretmek","d":"Mitoz, ana hücreyle aynı kalıtsal bilgiye sahip iki hücre üretir. Bunun için kalıtsal madde eşit paylaşılmalıdır."},{"t":"Anafazın katkısı","a":"Eşit dağılım","d":"Anafazda kromatitlerin eşit dağılması, her hücrenin aynı genleri almasını sağlar. Bu, özdeşliğin temelidir."},{"t":"Sonuç","a":"Genetik kararlılık","d":"Böylece büyüme ve onarımda hücreler aynı kalıtsal bilgiyi taşır. Mitozun amacı yerine gelir."}],"ans":"Özdeş (aynı kalıtsal bilgiye sahip) hücre üretme amacına hizmet eder."},{"q":"Anafaz evresi metafaz kontrol noktasının onayından sonra başlar; bu kontrol noktasının görevi nedir?","steps":[{"t":"Kontrol noktası","a":"Bağlanmayı denetler","d":"Metafaz kontrol noktası, tüm kromozomların iğ ipliklerine doğru bağlanıp bağlanmadığını denetler. Eksik bağlantı varsa anafaz başlamaz."},{"t":"Onay","a":"Tüm bağlantılar tamam","d":"Tüm kromozomlar her iki kutuptan iplikle doğru bağlandığında kontrol noktası onay verir. Ancak bundan sonra anafaz başlar."},{"t":"Amaç","a":"Hatasız dağılım","d":"Bu denetim, kromatitlerin yanlış dağılmasını önler. Böylece her kutba doğru sayıda kromozom gider."}],"ans":"Tüm kromozomların iğ ipliklerine doğru bağlandığını denetlemek."},{"q":"Anafazda kinetokor ile sentromer arasındaki ilişki nedir?","steps":[{"t":"Sentromer","a":"Kromozom üzerinde bölge","d":"Sentromer, kromozomun belirli bir bölgesidir ve kardeş kromatitlerin birleştiği yerdir. Anafaza kadar bu bölge bağlantıyı sağlar."},{"t":"Kinetokor","a":"Sentromer üstünde protein yapı","d":"Kinetokor, sentromer bölgesi üzerinde oluşan protein kompleksidir. İğ iplikleri kromozoma kinetokor aracılığıyla tutunur."},{"t":"Anafazda işlev","a":"Bağlantı noktası","d":"Anafazda iğ iplikleri kinetokora bağlanarak kromatitleri kutuplara çeker. Sentromer ise kromatitlerin ayrıldığı noktadır."}],"ans":"Kinetokor, sentromer bölgesi üzerinde iğ ipliklerinin tutunduğu protein yapısıdır."},{"q":"Anafaz mitozun en kısa süren evresi olarak bilinir; bu evrede hangi tek temel olay tamamlanır?","steps":[{"t":"Süre özelliği","a":"Çok kısa","d":"Anafaz, mitoz evreleri içinde en kısa sürede tamamlanan evredir. Olaylar hızlı ve eş zamanlı gerçekleşir."},{"t":"Temel olay","a":"Kromatit ayrımı","d":"Bu evrede tek temel olay, kardeş kromatitlerin ayrılıp zıt kutuplara çekilmesidir. Bu olay hızla gerçekleşir."},{"t":"Sonuç","a":"İki özdeş takım","d":"Olay bitince hücrenin iki kutbunda da özdeş kromozom takımları oluşur. Bu, telofazı başlatır."}],"ans":"Kardeş kromatitlerin ayrılıp zıt kutuplara çekilmesi."},{"q":"Anafazda her kutba giden kromozom takımının genetik içerik bakımından özelliği nedir?","steps":[{"t":"Kromatit kökeni","a":"Aynı kromozomdan","d":"Her kromozomun iki kardeş kromatiti, interfazda aynı kromozomun kopyalanmasıyla oluşmuştu. Bu nedenle ikisi de aynı genleri taşır."},{"t":"Dağılım","a":"Birer kromatit","d":"Anafazda bir kromatit bir kutba, özdeş eşi öteki kutba gider. Böylece her kutup aynı genleri alır."},{"t":"Sonuç","a":"Özdeş içerik","d":"Her iki kutuptaki kromozom takımı genetik olarak birbirinin aynısıdır. Bu, mitozun özdeşlik özelliğini sağlar."}],"ans":"Her iki kutuptaki kromozom takımı genetik olarak özdeştir."},{"q":"Anafazda iğ ipliklerinin kısalması için gereken enerjiyi sağlayan molekül nedir?","steps":[{"t":"Enerji gereksinimi","a":"Hareket enerji ister","d":"Kromatitlerin kutuplara çekilmesi aktif bir olaydır ve enerji gerektirir. İğ iplikleri bu enerjiyle çalışır."},{"t":"Enerji kaynağı","a":"ATP","d":"Hücredeki temel enerji molekülü olan ATP, iğ ipliklerinin kısalmasına güç sağlar. Motor proteinler ATP'yi kullanır."},{"t":"Sonuç","a":"Hareket gerçekleşir","d":"ATP enerjisiyle mikrotübüller kısalır ve kromatitler taşınır. Enerji olmadan hareket gerçekleşmez."}],"ans":"ATP enerji molekülüdür."},{"q":"Anafazda diploit (2n) bir hücrede her kutba giden kromozom takımı kaç n olur?","steps":[{"t":"Başlangıç","a":"2n hücre","d":"Hücre diploit, yani 2n kromozom takımına sahiptir. Her kromozom çift kromatitlidir."},{"t":"Kromatit dağılımı","a":"Eşit paylaşım","d":"Anafazda her kromozomun bir kromatiti her kutba gider. Kutuplara giden kromozom sayısı ana hücreyle aynıdır."},{"t":"Sonuç","a":"2n korunur","d":"Her kutup yine 2n kromozom takımı alır. Çünkü mitozda kromozom sayısı korunur, yarıya inmez."}],"ans":"Her kutup yine 2n kromozom takımı alır."},{"q":"Anafazda kromatitlerin kutuplara taşınmasında rol oynayan motor proteinlerin işlevi nedir?","steps":[{"t":"Motor protein","a":"Mikrotübül üzerinde yürür","d":"Motor proteinler mikrotübüller boyunca hareket edebilen özel proteinlerdir. Bunlar ATP enerjisi kullanır."},{"t":"İşlev","a":"Çekme ve düzenleme","d":"Bu proteinler kromozomları mikrotübül boyunca kutuplara taşınmasına yardımcı olur. Ayrıca mikrotübül kısalmasını düzenler."},{"t":"Sonuç","a":"Düzenli hareket","d":"Motor proteinler sayesinde kromatitler düzenli ve eş zamanlı taşınır. Bu, eşit dağılımı destekler."}],"ans":"Kromozomların mikrotübüller boyunca kutuplara taşınmasını sağlar."},{"q":"Anafazda kutuplar arası iğ ipliklerinin uzaması hücrenin hangi sonraki olayına hazırlık sağlar?","steps":[{"t":"İplik uzaması","a":"Kutuplar uzaklaşır","d":"Kutuplar arası iplikler uzayarak iki kutbu birbirinden uzaklaştırır. Hücre boyca uzamaya başlar."},{"t":"Hücre şekli","a":"Uzar ve incelir","d":"Hücre uzadıkça orta bölge belirginleşir. Bu bölge ileride bölünme yeri olacaktır."},{"t":"Hazırlık","a":"Sitokineze zemin","d":"Bu uzama, sitoplazmanın ortadan ikiye bölünmesine zemin hazırlar. Telofaz ve sitokinez için ön koşuldur."}],"ans":"Sitoplazma bölünmesine (sitokineze) zemin hazırlar."}],"zor":[{"q":"İnsanda somatik bir hücre (2n=46) anafaza girdiğinde sentromerler bölündükten sonra hücrede toplam kaç kromozom bulunur ve her kutba kaçı gider?","steps":[{"t":"Anafaz öncesi","a":"46 çift kromatitli","d":"İnsan somatik hücresi 2n=46 kromozom taşır. Anafaz başında her kromozom iki kardeş kromatitten oluşur."},{"t":"Sentromer bölünmesi","a":"92 kromozom oluşur","d":"Sentromerler bölününce 46 kromozomun her biri ikiye ayrılır. Her kromatit ayrı kromozom sayıldığı için hücrede geçici olarak 92 kromozom bulunur."},{"t":"Kutuplara dağılım","a":"Her kutba 46","d":"Bu 92 kromozom iki kutba eşit dağılır. Her kutba ana hücreyle aynı sayıda, yani 46 kromozom gider."}],"ans":"Geçici olarak 92 kromozom bulunur; her kutba 46 kromozom gider."},{"q":"Anafazda separaz enziminin kohezin proteinlerini kesmesi kromatit ayrılması için neden zorunludur?","steps":[{"t":"Kohezinin rolü","a":"Kromatitleri bağlar","d":"Kohezin proteinleri kardeş kromatitleri özellikle sentromer çevresinde bir arada tutar. Bu bağ anafaza kadar korunur."},{"t":"Separaz etkisi","a":"Kohezini keser","d":"Separaz enzimi anafaz başında kohezin proteinlerini keser. Böylece kromatitler arasındaki yapışıklık ortadan kalkar."},{"t":"Sonuç","a":"Ayrılma serbestleşir","d":"Kohezin kesildiğinde iğ iplikleri kromatitleri zıt kutuplara çekebilir. Separaz olmadan kromatitler ayrılamaz ve dağılım gerçekleşmez."}],"ans":"Kohezin kesilmeden kromatitler ayrılamaz; separaz bu bağı keserek ayrılmayı başlatır."},{"q":"Anafaz başlamadan önce APC (anafaz destekleyici kompleks) sekürin proteinini yıkar; bu olay separazı nasıl etkiler?","steps":[{"t":"Sekürinin görevi","a":"Separazı baskılar","d":"Sekürin proteini, separaz enzimine bağlanarak onu etkisiz tutar. Bu sayede separaz erken çalışıp kromatitleri vaktinden önce ayıramaz."},{"t":"APC etkisi","a":"Sekürin yıkılır","d":"Metafaz kontrol noktası onay verince APC kompleksi sekürini yıkım için işaretler. Yıkılan sekürin separazı serbest bırakır."},{"t":"Sonuç","a":"Separaz aktifleşir","d":"Serbest kalan separaz kohezini keserek kromatit ayrılmasını başlatır. Böylece anafaz doğru zamanda gerçekleşir."}],"ans":"Sekürin yıkılınca separaz serbest kalır ve aktifleşip kromatitleri ayırır."},{"q":"Anafaz A ve anafaz B süreçlerinde mikrotübül davranışları nasıl farklılaşır?","steps":[{"t":"Anafaz A","a":"Kinetokor iplikleri kısalır","d":"Anafaz A sürecinde kinetokora bağlı mikrotübüller kısalarak kromozomları kutuplara çeker. Kromozom-kutup mesafesi azalır."},{"t":"Anafaz B","a":"Kutup iplikleri uzar","d":"Anafaz B sürecinde kutuplar arası mikrotübüller uzar ve kayar. Bu, iki kutbu birbirinden uzaklaştırır."},{"t":"Birleşik etki","a":"Tam ayrılma","d":"A sürecinde kromozomlar kutba yaklaşırken B sürecinde kutuplar uzaklaşır. İki süreç birlikte kromozom takımlarını iyice ayırır."}],"ans":"Anafaz A'da kinetokor iplikleri kısalır; anafaz B'de kutup iplikleri uzayarak kutuplar uzaklaşır."},{"q":"Anafazda kromatit ayrılması eşzamanlı (senkron) gerçekleşmezse hücrede hangi sayısal bozukluk oluşabilir?","steps":[{"t":"Eşzamanlı ayrılma","a":"Normal beklenti","d":"Normalde tüm kromatitler aynı anda ayrılıp zıt kutuplara dağılır. Bu, eşit ve özdeş takımlar oluşturur."},{"t":"Hatalı ayrılma","a":"Ayrılmama (nondisjunction)","d":"Bir kromozomun kromatitleri ayrılmazsa ikisi de aynı kutba gider. Buna kromozom ayrılmaması (nondisjunction) denir."},{"t":"Sonuç","a":"Anöploidi","d":"Bir hücre fazla, diğeri eksik kromozomlu olur. Bu sayısal bozukluğa anöploidi denir ve hücre işlevini bozar."}],"ans":"Kromatitler ayrılmazsa anöploidi (fazla/eksik kromozomlu hücre) oluşur."},{"q":"Anafazda kinetokor mikrotübüllerinin \"+\" ucundaki tübülin alt birimlerinin kaybı kromozom hareketini nasıl açıklar?","steps":[{"t":"Mikrotübül yapısı","a":"Tübülinden oluşur","d":"Mikrotübüller tübülin protein alt birimlerinin uç uca eklenmesiyle oluşur. Uçlardan birime ekleme veya çıkarma olabilir."},{"t":"Uç kaybı","a":"Kinetokor ucundan kısalma","d":"Anafazda kinetokora bağlı uçtan (+ ucu) tübülin alt birimleri ayrılır. Bu, mikrotübülün kısalmasına yol açar."},{"t":"Hareket","a":"Kromozom kutba çekilir","d":"Kinetokor, kısalan mikrotübülün ucuna tutunmaya devam ederek kromozomu kutba doğru sürükler. Böylece kromozom hareket eder."}],"ans":"+ ucundan tübülin kaybıyla mikrotübül kısalır ve kinetokor kromozomu kutba çeker."},{"q":"Anafaz hareketi sırasında oluşan çekme kuvvetinin \"Pac-Man\" modeli ile açıklanan kısmı nedir?","steps":[{"t":"Pac-Man modeli","a":"Kinetokorda yıkım","d":"Bu modelde kinetokor, tutunduğu mikrotübül ucundaki tübülini sökerek kromozomu kutba doğru ilerletir. Kinetokor adeta ipi yiyerek ilerler."},{"t":"Diğer mekanizma","a":"Kutupta geri çekme","d":"İkinci mekanizmada mikrotübül kutup ucundan da kısaltılır. İki mekanizma birlikte kromozomu çeker."},{"t":"Anafaz A katkısı","a":"Kutba yaklaşma","d":"Pac-Man mekanizması anafaz A'da kromozomun kutba yaklaşmasını sağlar. Böylece kromatitler kutuplara taşınır."}],"ans":"Kinetokorun, tutunduğu mikrotübül ucundaki tübülini sökerek kromozomu kutba çekmesidir."},{"q":"Anafazda kromozomların kutuplara çekilmesi mikrotübül kayma değil kısalma sayesinde gerçekleştiği nasıl gösterilebilir?","steps":[{"t":"Gözlem","a":"Mikrotübül boyu azalır","d":"Anafazda kinetokor mikrotübüllerinin boyu ölçülürse giderek kısaldığı görülür. Toplam mikrotübül uzunluğu azalır."},{"t":"Kayma olsaydı","a":"Boy değişmezdi","d":"Eğer hareket yalnızca mikrotübüllerin birbiri üzerinde kayması ile olsaydı mikrotübül boyu sabit kalırdı. Oysa boy azalmaktadır."},{"t":"Sonuç","a":"Kısalma esastır","d":"Boyun azalması, anafaz A hareketinin mikrotübül kısalmasıyla gerçekleştiğini gösterir. Bu, kromozomların kutba çekilmesini açıklar."}],"ans":"Kinetokor mikrotübüllerinin boyunun giderek azalması, hareketin kısalmayla olduğunu gösterir."},{"q":"Anafazda iğ ipliği kontrol noktasının (SAC) inaktif hâle gelmesi neden anafazı başlatır?","steps":[{"t":"SAC görevi","a":"Anafazı durdurur","d":"İğ ipliği kontrol noktası (SAC), tüm kinetokorlar mikrotübüllere doğru bağlanana kadar anafazın başlamasını engeller. Bağlanmamış kinetokor bir uyarı sinyali üretir."},{"t":"İnaktivasyon","a":"Tüm bağlantı tamam","d":"Tüm kinetokorlar iki kutuptan doğru bağlandığında uyarı sinyali kesilir ve SAC inaktif olur. Engelleyici sinyal ortadan kalkar."},{"t":"Sonuç","a":"APC aktifleşir","d":"SAC inaktif olunca APC kompleksi serbest kalır, sekürini yıkar ve separaz aktifleşir. Böylece kromatitler ayrılarak anafaz başlar."}],"ans":"SAC inaktif olunca APC serbest kalır, sekürin yıkılır ve separaz kromatitleri ayırarak anafaz başlar."},{"q":"Anafazda 2n=24 kromozomlu bir bitki hücresinde hareket eden tüm kromatitlerin toplam DNA içeriği ana hücrenin G1 evresine göre nasıldır?","steps":[{"t":"G1 içeriği","a":"2C DNA","d":"G1 evresinde hücre 2n=24 kromozomlu ve 2C miktarında DNA içerir. Henüz kopyalama yapılmamıştır."},{"t":"S evresi sonrası","a":"4C DNA","d":"S evresinde DNA kopyalandığı için kromatit sayısı ikiye katlanır. Anafaz başında toplam DNA 4C miktarındadır."},{"t":"Anafazda","a":"Toplam 4C, kutba 2C","d":"Anafazda hücrede hâlâ toplam 4C DNA bulunur ve henüz bölünmemiştir. Bu DNA kutuplara eşit dağılır, her kutba 2C gider."}],"ans":"Anafazda toplam DNA 4C (G1'in iki katı); her kutba 2C dağılır."},{"q":"Anafazda kohezin proteinlerinin sentromer çevresinde profazdan beri korunmuş olması neden önemlidir?","steps":[{"t":"Profazda durum","a":"Kol kohezini ayrılır","d":"Profaz sırasında kromatit kolları boyunca bulunan kohezinlerin büyük kısmı uzaklaştırılır. Ancak sentromer çevresindeki kohezin korunur."},{"t":"Korumanın amacı","a":"Erken ayrılmayı önler","d":"Sentromerdeki kohezinin korunması, kromatitlerin metafaza kadar bir arada kalmasını sağlar. Böylece kromozomlar düzgün dizilir ve doğru bağlanır."},{"t":"Anafazda","a":"Son anda kesilir","d":"Anafazda separaz bu son kohezini de keser ve kromatitler tam o anda ayrılır. Bu zamanlama eşit dağılım için kritiktir."}],"ans":"Sentromerdeki kohezin, kromatitlerin metafaza kadar erken ayrılmasını önler ve doğru dizilimi sağlar."},{"q":"Anafazda kromozom hareket hızı yaklaşık dakikada bir mikrometre kadardır; bu yavaş hızın işlevsel anlamı nedir?","steps":[{"t":"Hız özelliği","a":"Yavaş ve kontrollü","d":"Anafazda kromozomlar yaklaşık dakikada 1 mikrometre gibi düşük bir hızla hareket eder. Bu, hücre içi olaylar için kontrollü bir hızdır."},{"t":"İşlevsel anlam","a":"Hatasız taşıma","d":"Yavaş hareket, kromozomların birbirine dolanmadan ve zarar görmeden taşınmasını sağlar. Hızlı hareket kopma riskini artırırdı."},{"t":"Sonuç","a":"Doğru dağılım","d":"Kontrollü hız, her kutba doğru kromozom takımının ulaşmasını güvence altına alır. Bu, genetik kararlılığı korur."}],"ans":"Yavaş ve kontrollü hareket kromozomların zarar görmeden ve hatasız taşınmasını sağlar."},{"q":"Anafazda iki kutbun kromozom takımlarının özdeş olması, mitozun mayozdan ayrılan hangi temel özelliğini yansıtır?","steps":[{"t":"Mitoz anafaz","a":"Kromatitler ayrılır","d":"Mitoz anafazda kardeş kromatitler ayrılır ve her kutba özdeş takım gider. Sonuçta oluşan hücreler ana hücreyle aynıdır."},{"t":"Mayoz farkı","a":"Homologlar ayrılır","d":"Mayoz I anafazda ise kardeş kromatitler değil homolog kromozomlar ayrılır. Bu, kromozom sayısını yarıya indirir."},{"t":"Temel özellik","a":"Özdeşlik","d":"Mitozun kardeş kromatitleri ayırması, özdeş hücre üretme özelliğini yansıtır. Mayoz ise çeşitlilik ve sayı azalması sağlar."}],"ans":"Mitozda kardeş kromatitlerin ayrılıp özdeş hücre üretme özelliğini yansıtır."},{"q":"Anafazda kolşisin gibi mikrotübül oluşumunu engelleyen bir madde varsa kromatit ayrılması ve dağılımı nasıl etkilenir?","steps":[{"t":"Kolşisin etkisi","a":"İğ ipliği oluşmaz","d":"Kolşisin, tübülin alt birimlerinin birleşmesini engelleyerek iğ ipliklerinin (mikrotübül) oluşumunu durdurur. İğ ipliği olmadan kromozomlar tutunamaz."},{"t":"Ayrılma","a":"Kutuplara çekilemez","d":"Sentromer bölünse bile kromatitler iğ ipliği olmadan kutuplara çekilemez. Kromozomlar dağılamaz ve ortada kalır."},{"t":"Sonuç","a":"Poliploidi olasılığı","d":"Hücre bölünemediği için kromozom sayısı katlanmış bir hücre oluşabilir. Bu yüzden kolşisin poliploit hücre eldesinde kullanılır."}],"ans":"İğ ipliği oluşmadığından kromatitler kutuplara dağılamaz; kromozom sayısı katlanmış (poliploit) hücre oluşabilir."},{"q":"Anafazda her kromatitin kendi kinetokorundan tek bir kutba bağlanmış olması (amfitelik bağlanma) neden gereklidir?","steps":[{"t":"Amfitelik bağlanma","a":"Zıt kutuplara bağlı","d":"Doğru bağlanmada bir kromozomun iki kardeş kromatitinin kinetokorları zıt kutuplardan gelen ipliklere bağlanır. Buna amfitelik bağlanma denir."},{"t":"Yanlış bağlanma","a":"Aynı kutba bağlanma","d":"Eğer her iki kinetokor aynı kutba bağlanırsa kromatitler aynı kutba gider. Bu, eşit olmayan dağılıma yol açar."},{"t":"Gereklilik","a":"Eşit dağılım","d":"Amfitelik bağlanma, anafazda kromatitlerin farklı kutuplara gitmesini garanti eder. Bu olmadan kromozom dağılımı hatalı olur."}],"ans":"Amfitelik bağlanma, kardeş kromatitlerin zıt kutuplara eşit dağılmasını garanti ettiği için gereklidir."}]}},"telofazMitoz":{"ilkokul":{"kolay":[{"q":"Mitozun telofaz evresinde kutuplara ulaşan kromozomlara ne olur?","steps":[{"t":"Kromozomların durumu","a":"Kutuplara ulaştılar","d":"Anafaz sonunda kromozomlar hücrenin iki kutbuna toplanmıştı. Telofazda bu kromozomlar artık hareketsizdir."},{"t":"İplik hâline dönme","a":"Tekrar açılır","d":"Kromozomlar telofazda gevşeyerek tekrar ince iplik (kromatin) hâline döner. Yani kalın görünümlerini kaybeder."}],"ans":"Tekrar gevşeyip ince iplik (kromatin) hâline döner."},{"q":"Telofazda hücrenin her kutbunda yeniden oluşan yapı nedir?","steps":[{"t":"Çekirdek zarı","a":"Kromozomları sarar","d":"Telofazda her kromozom kümesinin etrafında çekirdek zarı yeniden oluşur. Bu zar kromozomları içine alır."},{"t":"İki çekirdek","a":"Her kutupta bir tane","d":"Böylece hücrenin her iki kutbunda birer çekirdek oluşur. Bir hücre içinde geçici olarak iki çekirdek bulunur."}],"ans":"Her kutupta yeniden çekirdek zarı (çekirdek) oluşur."},{"q":"Mitozda sitoplazmanın ikiye bölünmesi olayına ne ad verilir?","steps":[{"t":"Olayı tanıma","a":"Sitoplazma ayrılır","d":"Çekirdek bölünmesinden sonra hücrenin sitoplazması da ikiye ayrılır. Bu sayede iki ayrı hücre oluşur."},{"t":"İsmi","a":"Sitokinez","d":"Sitoplazmanın bölünmesi olayına sitokinez denir. Bu olay genellikle telofazla birlikte gerçekleşir."}],"ans":"Sitokinez (sitoplazma bölünmesi) denir."},{"q":"Hayvan hücresinde sitoplazma bölünürken hücrenin ortasında ne oluşur?","steps":[{"t":"Ortadan daralma","a":"Hücre içeri çöker","d":"Hayvan hücresinde sitoplazma bölünürken hücre ortadan içeri doğru girinti yapar. Hücre yüzeyi daralmaya başlar."},{"t":"Boğumlanma","a":"İkiye ayrılır","d":"Bu girinti gittikçe derinleşir ve hücreyi ortadan boğar. Buna boğumlanma denir ve hücre ikiye ayrılır."}],"ans":"Ortadan boğumlanma (girinti) oluşur."},{"q":"Mitoz sonunda telofaz ve sitokinez tamamlandığında kaç hücre oluşur?","steps":[{"t":"Bölünme sonucu","a":"Bir hücre ikiye","d":"Mitoz, bir ana hücreyi ikiye bölmek için gerçekleşir. Telofaz ve sitokinez bu bölünmeyi tamamlar."},{"t":"Hücre sayısı","a":"İki hücre","d":"Sonuçta bir ana hücreden iki yeni hücre oluşur. Bu iki hücre birbirinin aynısıdır."}],"ans":"İki hücre oluşur."}],"zor":[{"q":"Telofaz sonunda oluşan iki hücre birbirine göre nasıldır?","steps":[{"t":"Bölünme türü","a":"Mitozla oluşur","d":"Bu iki hücre mitoz bölünme sonucu oluşmuştur. Mitozda kalıtsal madde eşit paylaşılır."},{"t":"Özelliği","a":"Birbirinin aynısı","d":"Oluşan iki hücre hem kromozom sayısı hem de kalıtsal bilgi bakımından birbirinin aynısıdır. Ayrıca ana hücreye de benzerler."}],"ans":"Birbirinin ve ana hücrenin aynısıdır (özdeştir)."},{"q":"Bitki hücresinde sitokinez sırasında ortada oluşan yapı hayvan hücresinden nasıl ayrılır?","steps":[{"t":"Bitki hücresi","a":"Ara plak oluşur","d":"Bitki hücresinin sert çeperi olduğu için boğumlanma yapamaz. Bunun yerine hücrenin ortasında ara plak adı verilen bir bölme oluşur."},{"t":"Hayvan hücresi","a":"Boğumlanma yapar","d":"Hayvan hücresinde ise hücre ortadan içeri girinti yaparak boğumlanır. Böylece iki hücre ayrılır."}],"ans":"Bitkide ortada ara plak (bölme) oluşur; hayvanda boğumlanma olur."},{"q":"Telofazda iğ iplikleri ne olur ve bu neden gereklidir?","steps":[{"t":"İpliklerin görevi","a":"Görevini tamamladı","d":"İğ iplikleri kromozomları kutuplara taşıma görevini anafazda tamamlamıştır. Telofazda artık bu görev bitmiştir."},{"t":"Kaybolma","a":"İplikler çözülür","d":"Telofazda iğ iplikleri çözülerek kaybolur. Böylece hücre yeniden normal yapısına döner."}],"ans":"İğ iplikleri görevini bitirdiği için çözülerek kaybolur."},{"q":"Telofazda çekirdek zarının yeniden oluşması hücre için neden gereklidir?","steps":[{"t":"Çekirdek zarının görevi","a":"Kromozomları korur","d":"Çekirdek zarı, kalıtsal madde olan kromozomları sarıp koruyan yapıdır. Profazda kromozomların serbest kalması için kaybolmuştu."},{"t":"Yeniden oluşma","a":"Koruma sağlanır","d":"Telofazda çekirdek zarı tekrar oluşarak kromozomları sarar. Böylece kalıtsal madde korunur ve hücre normal işleyişine döner."}],"ans":"Kromozomları (kalıtsal maddeyi) sarıp korumak için gereklidir."},{"q":"Telofazda kaybolan çekirdekçik için ne olur?","steps":[{"t":"Çekirdekçiğin durumu","a":"Profazda kaybolmuştu","d":"Çekirdekçik bölünme başında, profazda kaybolmuştu. Bölünme boyunca görünmez."},{"t":"Yeniden oluşma","a":"Tekrar belirir","d":"Telofazda her yeni çekirdeğin içinde çekirdekçik yeniden belirir. Böylece çekirdek normal yapısına kavuşur."}],"ans":"Çekirdekçik telofazda yeniden oluşur (belirir)."}]},"ortaokul":{"kolay":[{"q":"Telofazda kutuplara ulaşan kromozomların kromatin hâline dönmesi ne anlama gelir?","steps":[{"t":"Kromozom durumu","a":"Yoğun ve kalın","d":"Bölünme sırasında kromozomlar yoğunlaşarak kalın ve belirgin yapılar hâline gelmişti. Bu, taşınmayı kolaylaştırmıştı."},{"t":"Kromatine dönme","a":"Gevşer ve incelir","d":"Telofazda kromozomlar gevşeyerek tekrar ince iplik, yani kromatin hâline döner. Böylece çekirdek normal işleyişine hazırlanır."}],"ans":"Kromozomların gevşeyip tekrar ince iplik (kromatin) hâline gelmesi demektir."},{"q":"Telofazda hücrenin her iki kutbunda çekirdek zarının oluşması neyi sağlar?","steps":[{"t":"Çekirdek zarı","a":"Kromozomları sarar","d":"Telofazda her kromozom kümesinin etrafında çekirdek zarı yeniden oluşur. Bu zar kromozomları içine alır."},{"t":"İki çekirdek","a":"Her kutupta bir","d":"Böylece hücrede geçici olarak iki ayrı çekirdek oluşur. Bu çekirdekler sitokinez sonrası iki hücreye dağılır."}],"ans":"Her kutupta birer çekirdek oluşmasını sağlar."},{"q":"Mitozda sitokinez ile telofaz arasındaki ilişki nedir?","steps":[{"t":"Telofaz","a":"Çekirdek bölünmesi","d":"Telofaz, çekirdek bölünmesinin (mitozun) son evresidir. Bu evrede iki yeni çekirdek oluşur."},{"t":"Sitokinez","a":"Sitoplazma bölünmesi","d":"Sitokinez, sitoplazmanın ikiye bölünmesidir ve genellikle telofazla birlikte gerçekleşir. İkisi birlikte bölünmeyi tamamlar."}],"ans":"Sitokinez, telofazla birlikte gerçekleşip sitoplazmayı bölerek iki hücreyi oluşturur."},{"q":"Hayvan hücresinde boğumlanma nasıl gerçekleşir?","steps":[{"t":"Daralma başlangıcı","a":"Ortadan girinti","d":"Hayvan hücresinde sitokinez sırasında hücre zarı ortadan içeri doğru girinti yapar. Bu girinti hücre çevresini sarar."},{"t":"Boğum oluşumu","a":"İkiye ayrılma","d":"Girinti derinleşerek hücreyi ortadan boğar ve ikiye ayırır. Bu olaya boğumlanma denir."}],"ans":"Hücre zarı ortadan içeri girinti yaparak hücreyi boğup ikiye ayırır."},{"q":"Bitki hücresinde ara plak (orta lamel) hangi yönde gelişerek hücreyi böler?","steps":[{"t":"Ara plak oluşumu","a":"Ortada başlar","d":"Bitki hücresinde sitokinez, hücrenin tam ortasında ara plak oluşumuyla başlar. Bu yapı küçük keseciklerin birleşmesiyle meydana gelir."},{"t":"Gelişme yönü","a":"Ortadan kenara","d":"Ara plak ortadan başlayıp hücre çeperine doğru genişler. Çepere ulaşınca hücreyi ikiye böler."}],"ans":"Ortadan başlayıp hücre çeperine (kenara) doğru genişleyerek böler."}],"zor":[{"q":"Telofazda çekirdek zarının yeniden oluşması profazdaki olayın tersi sayılır; bu iki olayı karşılaştırınız.","steps":[{"t":"Profaz","a":"Çekirdek zarı erir","d":"Profazda çekirdek zarı parçalanarak erir ve kromozomlar serbest kalır. Bu, iğ ipliklerinin kromozomlara ulaşmasını sağlar."},{"t":"Telofaz","a":"Çekirdek zarı oluşur","d":"Telofazda ise çekirdek zarı kromozomların etrafında yeniden oluşur. Kromozomlar tekrar zarla çevrelenir."},{"t":"Karşılaştırma","a":"Ters olaylar","d":"Profazda kaybolan çekirdek zarı telofazda geri gelir. Bu yüzden telofaz, profazın tersi olaylar dizisi gibi düşünülebilir."}],"ans":"Profazda zar erirken telofazda zar yeniden oluşur; iki olay birbirinin tersidir."},{"q":"Bitki ve hayvan hücrelerinde sitokinezin farklı yollarla gerçekleşmesinin temel nedeni nedir?","steps":[{"t":"Bitki hücresi","a":"Sert çeper var","d":"Bitki hücresinin etrafında sert bir hücre çeperi bulunur. Bu çeper, hücrenin içeri doğru boğumlanmasını engeller."},{"t":"Hayvan hücresi","a":"Çeper yok","d":"Hayvan hücresinde sert çeper olmadığı için hücre zarı esnektir. Bu yüzden zar içeri girinti yaparak boğumlanabilir."},{"t":"Sonuç","a":"Farklı yöntem","d":"Çeperi olan bitki ara plak oluştururken, çepersiz hayvan boğumlanır. Yani fark, hücre çeperinin varlığından kaynaklanır."}],"ans":"Bitki hücresinde sert çeperin bulunması; çeper boğumlanmayı engellediği için ara plak oluşur."},{"q":"Telofazda iğ ipliklerinin kaybolması ve çekirdekçiğin yeniden oluşması aynı anda gerçekleşir; bu olaylar hücreyi hangi duruma hazırlar?","steps":[{"t":"İğ ipliklerinin kaybı","a":"Görev bitti","d":"İğ iplikleri kromozomları taşıma görevini tamamladığı için telofazda çözülerek kaybolur. Hücre iskeleti normal düzenine döner."},{"t":"Çekirdekçiğin oluşması","a":"Yeniden belirir","d":"Telofazda her çekirdekte çekirdekçik yeniden oluşur. Çekirdekçik, ribozom yapımı için gereklidir."},{"t":"Hazırlık","a":"Normal yaşama","d":"Bu olaylar, yeni hücrelerin normal yaşam ve işlevlerine dönmesini sağlar. Hücre interfaza, yani normal yaşam evresine hazırlanır."}],"ans":"Yeni hücrelerin normal yaşam evresine (interfaza) dönmesine hazırlar."},{"q":"Telofaz ve sitokinez sonunda oluşan iki hücrenin kromozom sayısı ana hücreyle aynıdır; bu sonuç mitozun hangi özelliğini gösterir?","steps":[{"t":"Kromozom dağılımı","a":"Eşit paylaşıldı","d":"Anafazda kromatitler iki kutba eşit dağılmış, telofazda iki çekirdek oluşmuştu. Sitokinezle bu çekirdekler iki hücreye ayrıldı."},{"t":"Sonuç sayı","a":"Aynı kalır","d":"Her yeni hücre, ana hücreyle aynı sayıda kromozoma sahiptir. Yani 2n hücreden 2n hücreler oluşur."},{"t":"Özellik","a":"Sayı korunur","d":"Bu durum mitozun kromozom sayısını koruma özelliğini gösterir. Mitoz, eşeysiz çoğalma ve onarım için bu özelliği kullanır."}],"ans":"Mitozun kromozom sayısını koruyarak özdeş hücre üretme özelliğini gösterir."},{"q":"Bir hücre telofazı tamamlayıp sitokinez gerçekleşmezse nasıl bir hücre ortaya çıkar?","steps":[{"t":"Telofaz tamam","a":"İki çekirdek oluşur","d":"Telofazda iki ayrı çekirdek oluşur ve kromozomlar bu çekirdeklere dağılır. Çekirdek bölünmesi tamamlanır."},{"t":"Sitokinez yoksa","a":"Sitoplazma bölünmez","d":"Eğer sitokinez gerçekleşmezse sitoplazma ikiye ayrılmaz. İki çekirdek aynı sitoplazmada kalır."},{"t":"Sonuç","a":"Çok çekirdekli hücre","d":"Böylece tek bir hücre içinde iki (veya daha fazla) çekirdek bulunur. Buna çok çekirdekli hücre denir."}],"ans":"Tek sitoplazmada iki çekirdek bulunan çok çekirdekli bir hücre oluşur."}]},"lise":{"kolay":[{"q":"Telofazda kutuplara ulaşan kromozomların kromatin hâline dönmesinin işlevsel nedeni nedir?","steps":[{"t":"Yoğunlaşma nedeni","a":"Taşıma için yoğunlaşmıştı","d":"Kromozomlar bölünme sırasında yoğunlaşarak kalınlaşmıştı; bu, dolanmadan taşınmalarını sağlamıştı. Taşıma işi telofazda bitmiştir."},{"t":"Gevşeme","a":"Kromatine döner","d":"Telofazda kromozomlar gevşeyerek ince kromatin iplikleri hâline döner. Yoğun yapı çözülür."},{"t":"İşlevsel neden","a":"Gen okunabilir","d":"Gevşemiş kromatin üzerindeki genlere ulaşmak kolaylaşır. Böylece hücre protein üretimi gibi normal işlevlerini sürdürebilir."}],"ans":"Genlere ulaşılıp normal hücre işlevlerinin (gen okuma) yapılabilmesi için kromatine döner."},{"q":"Telofazda çekirdek zarının yeniden oluşumu hangi yapı parçalarından gerçekleşir?","steps":[{"t":"Zarın kaynağı","a":"Endoplazmik retikulum","d":"Telofazda çekirdek zarı, hücredeki endoplazmik retikulum zarlarının parçalarından yeniden oluşur. Bu zar parçaları kromozomların çevresinde toplanır."},{"t":"Birleşme","a":"Kromozomları sarar","d":"Zar parçaları her kutuptaki kromozom kümesinin etrafında birleşir. Böylece kromozomlar zarla çevrelenir."},{"t":"Sonuç","a":"İki çekirdek","d":"Her kutupta birer çekirdek zarı tamamlanır. Hücrede geçici olarak iki çekirdek oluşur."}],"ans":"Endoplazmik retikulum zar parçalarının kromozomlar çevresinde birleşmesiyle oluşur."},{"q":"Telofazda iğ ipliklerinin parçalanması mikrotübül seviyesinde nasıl açıklanır?","steps":[{"t":"İğ ipliği yapısı","a":"Mikrotübülden oluşur","d":"İğ iplikleri tübülin alt birimlerinden oluşan mikrotübüllerdir. Görevleri kromozomları kutuplara taşımaktı."},{"t":"Parçalanma","a":"Tübüline ayrışır","d":"Telofazda mikrotübüller tübülin alt birimlerine ayrışarak çözülür. Böylece iğ iplikleri kaybolur."},{"t":"Geri dönüşüm","a":"Yeniden kullanılır","d":"Açığa çıkan tübülin alt birimleri hücre tarafından depolanır ve gerektiğinde tekrar kullanılır. Hücre normal iskelet düzenine döner."}],"ans":"Mikrotübüller tübülin alt birimlerine ayrışarak çözülür ve kaybolur."},{"q":"Telofazda çekirdekçiğin yeniden oluşması hücre için neden önemlidir?","steps":[{"t":"Çekirdekçiğin görevi","a":"Ribozom üretir","d":"Çekirdekçik, ribozomların yapımının gerçekleştiği çekirdek bölgesidir. Profazda kaybolmuştu."},{"t":"Yeniden oluşma","a":"Telofazda belirir","d":"Telofazda her yeni çekirdekte çekirdekçik yeniden oluşur. Bu, ribozom yapımının yeniden başlamasını sağlar."},{"t":"Önem","a":"Protein sentezi","d":"Ribozomlar protein sentezi için gereklidir. Çekirdekçiğin oluşması, hücrenin protein üretimine dönmesini sağlar."}],"ans":"Ribozom yapımının yeniden başlaması ve protein sentezi için önemlidir."},{"q":"Telofaz ve sitokinez sonunda oluşan iki hücrenin kromozom sayısı ne olur?","steps":[{"t":"Anafaz dağılımı","a":"Eşit gitti","d":"Anafazda kromatitler iki kutba ana hücreyle aynı sayıda dağılmıştı. Her kutup eşit kromozom takımı almıştı."},{"t":"Telofaz-sitokinez","a":"İki hücre oluşur","d":"Telofazda iki çekirdek oluşur, sitokinezle sitoplazma bölünür. Böylece iki yeni hücre meydana gelir."},{"t":"Sonuç","a":"2n korunur","d":"Her yeni hücre, ana hücreyle aynı (2n) kromozom sayısına sahip olur. Mitozda kromozom sayısı korunur."}],"ans":"Her iki hücre de ana hücreyle aynı (2n) kromozom sayısına sahip olur."},{"q":"Hayvan hücresinde sitokinez sırasında oluşan boğumlanmayı sağlayan yapı nedir?","steps":[{"t":"Halka yapı","a":"Aktin halkası","d":"Hayvan hücresinde hücre zarının iç yüzünde aktin proteinlerinden bir halka oluşur. Bu halka hücrenin ortasını sarar."},{"t":"Daralma","a":"Halka büzülür","d":"Aktin halkası kasılarak büzülür ve hücre zarını içeri doğru çeker. Bu, hücrede girinti oluşturur."},{"t":"Sonuç","a":"Boğumlanma","d":"Halka gittikçe daralarak hücreyi ortadan boğar ve ikiye ayırır. Bu olaya boğumlanma denir."}],"ans":"Hücre zarının iç yüzündeki kasılan aktin (kontraktil) halkasıdır."},{"q":"Bitki hücresinde sitokinez sırasında ara plağı oluşturan yapılar nelerdir?","steps":[{"t":"Kesecikler","a":"Golgiden gelir","d":"Bitki hücresinde Golgi aygıtından kopan kesecikler hücrenin ortasına toplanır. Bu kesecikler hücre duvarı yapı maddeleri içerir."},{"t":"Birleşme","a":"Ara plak oluşur","d":"Kesecikler ortada birleşerek ara plağı (hücre plağı) oluşturur. Bu plak hücreyi ortadan bölmeye başlar."},{"t":"Gelişme","a":"Çepere doğru","d":"Ara plak ortadan çepere doğru genişleyerek yeni hücre çeperini oluşturur. Böylece iki hücre ayrılır."}],"ans":"Golgi aygıtından kopan keseciklerin ortada birleşmesiyle oluşur."},{"q":"Telofaz çekirdek bölünmesinin son evresi olarak hangi temel olayları içerir?","steps":[{"t":"Kromatin dönüşü","a":"Kromozomlar gevşer","d":"Telofazda kutuplara ulaşan kromozomlar gevşeyerek kromatin hâline döner. Yoğun yapı çözülür."},{"t":"Çekirdek oluşumu","a":"Zar ve çekirdekçik","d":"Her kutupta çekirdek zarı ve çekirdekçik yeniden oluşur. İki ayrı çekirdek meydana gelir."},{"t":"İğ ipliği kaybı","a":"Çözülür","d":"İğ iplikleri görevini tamamladığı için çözülerek kaybolur. Hücre iskeleti normal düzenine döner."}],"ans":"Kromatine dönüş, çekirdek zarı ve çekirdekçiğin oluşması, iğ ipliklerinin kaybolması."},{"q":"Telofaz ile sitokinez genellikle birlikte gerçekleşir; bu iki olay birbirinden nasıl ayrılır?","steps":[{"t":"Telofaz","a":"Çekirdek bölünmesi","d":"Telofaz, çekirdek bölünmesinin (karyokinez) son evresidir. Bu evrede iki çekirdek oluşur."},{"t":"Sitokinez","a":"Sitoplazma bölünmesi","d":"Sitokinez ise sitoplazmanın ikiye ayrılmasıdır. Bu, hücreyi fiziksel olarak iki parçaya böler."},{"t":"İlişki","a":"Birlikte tamamlar","d":"İki olay birlikte gerçekleşerek bir ana hücreden iki yeni hücre oluşmasını sağlar. Telofaz çekirdeği, sitokinez sitoplazmayı böler."}],"ans":"Telofaz çekirdeği, sitokinez ise sitoplazmayı böler; ikisi birlikte iki hücre oluşturur."},{"q":"Telofaz sonunda oluşan iki çekirdeğin genetik içeriği birbirine göre nasıldır?","steps":[{"t":"Kromatit kökeni","a":"Aynı kromozomdan","d":"Telofazdaki kromozomlar, interfazda kopyalanan kardeş kromatitlerden gelir. Bu kromatitler özdeş genler taşır."},{"t":"Dağılım","a":"Eşit paylaşıldı","d":"Anafazda her çekirdeğe bir kromatit gitmiş, telofazda iki çekirdek oluşmuştur. Her çekirdek aynı genleri almıştır."},{"t":"Sonuç","a":"Özdeş","d":"İki çekirdek genetik olarak birbirinin aynısıdır. Bu, mitozun özdeş hücre üretme özelliğini gösterir."}],"ans":"İki çekirdek genetik olarak birbirinin aynısıdır (özdeştir)."},{"q":"Telofazda çekirdek zarının oluşması için kromozomların önce kromatine dönmesi neden gerekir?","steps":[{"t":"Yoğun kromozom","a":"Zar saramaz","d":"Yoğunlaşmış kromozomların etrafına düzgün bir çekirdek zarı oluşturmak zordur. Yoğun yapı zar oluşumunu engelleyebilir."},{"t":"Kromatine dönüş","a":"Gevşer","d":"Kromozomlar gevşeyip kromatin hâline gelince çekirdek bölgesi daha düzenli hâle gelir. Zar parçaları bu yapı çevresine kolayca yerleşir."},{"t":"Sonuç","a":"Zar tamamlanır","d":"Gevşemiş kromatin etrafında çekirdek zarı düzgünce oluşur. Böylece sağlam bir çekirdek meydana gelir."}],"ans":"Gevşeyen kromatin etrafına çekirdek zarının düzgün oluşabilmesi için gereklidir."},{"q":"Telofazda iki yeni çekirdek oluştuktan sonra sitokinez gerçekleşmezse hücre ne tür bir yapı kazanır?","steps":[{"t":"Telofaz tamam","a":"İki çekirdek","d":"Telofazda iki ayrı çekirdek oluşur ve kromozomlar bu çekirdeklere dağılır. Çekirdek bölünmesi tamamlanır."},{"t":"Sitokinez yok","a":"Sitoplazma bölünmez","d":"Eğer sitokinez gerçekleşmezse sitoplazma ikiye ayrılmaz. İki çekirdek tek sitoplazmada kalır."},{"t":"Sonuç","a":"Çok çekirdekli","d":"Böylece tek hücrede iki veya daha fazla çekirdek bulunur. Buna çok çekirdekli (multinükleat) hücre denir."}],"ans":"Tek sitoplazmada birden fazla çekirdek taşıyan çok çekirdekli hücre oluşur."},{"q":"Telofazda gerçekleşen olaylar profazdaki olayların tersi olarak nasıl özetlenebilir?","steps":[{"t":"Profaz olayları","a":"Zar erir, kromatin yoğunlaşır","d":"Profazda çekirdek zarı ve çekirdekçik kaybolur, kromatin yoğunlaşarak kromozom olur. İğ iplikleri oluşur."},{"t":"Telofaz olayları","a":"Zar oluşur, kromozom gevşer","d":"Telofazda çekirdek zarı ve çekirdekçik yeniden oluşur, kromozomlar gevşeyerek kromatine döner. İğ iplikleri kaybolur."},{"t":"Karşılaştırma","a":"Ters olaylar","d":"Profazda kaybolan yapılar telofazda geri gelir, oluşan yapılar ise kaybolur. Bu yüzden telofaz profazın tersi gibidir."}],"ans":"Profazda kaybolan çekirdek zarı/çekirdekçik telofazda oluşur; yoğunlaşan kromatin gevşer; iğ iplikleri kaybolur."},{"q":"Hayvan ve bitki hücrelerinde sitokinezin farklı mekanizmalarla gerçekleşmesi hücre yapısının hangi farkıyla ilişkilidir?","steps":[{"t":"Hayvan hücresi","a":"Çeper yok, esnek zar","d":"Hayvan hücresinde sert çeper yoktur; yalnızca esnek hücre zarı bulunur. Bu zar içeri girinti yapabilir."},{"t":"Bitki hücresi","a":"Sert çeper var","d":"Bitki hücresinde sağlam ve sert bir hücre çeperi bulunur. Bu çeper hücrenin içe boğumlanmasını engeller."},{"t":"İlişki","a":"Çepere bağlı","d":"Çeperi olmayan hayvan boğumlanırken çeperi olan bitki ara plak oluşturur. Yani fark, hücre çeperinin varlığıyla ilişkilidir."}],"ans":"Bitkide sert hücre çeperinin bulunması, hayvanda bulunmamasıyla ilişkilidir."},{"q":"Mitoz sonunda telofaz ve sitokinez tamamlandığında oluşan hücrelerin ana hücreye göre boyutu nasıldır?","steps":[{"t":"Sitoplazma paylaşımı","a":"Bölünür","d":"Sitokinezde ana hücrenin sitoplazması iki yeni hücreye paylaştırılır. Her hücre sitoplazmanın yarısını alır."},{"t":"Boyut","a":"Daha küçük","d":"Bu nedenle yeni oluşan hücreler ana hücreden daha küçüktür. Hücreler henüz büyümemiştir."},{"t":"Büyüme","a":"İnterfazda büyür","d":"Yeni hücreler interfazda büyüyerek normal boyutlarına ulaşır. Daha sonra tekrar bölünmeye hazırlanabilir."}],"ans":"Yeni hücreler başlangıçta ana hücreden daha küçüktür; interfazda büyürler."}],"zor":[{"q":"Telofazda çekirdek zarının yeniden oluşmasında kromozom yüzeyindeki proteinler ve endoplazmik retikulum nasıl rol oynar?","steps":[{"t":"Kromozom yüzeyi","a":"Bağlanma sinyali","d":"Telofazda kromozom yüzeyindeki bazı proteinler, çekirdek zarı parçalarının bağlanması için sinyal görevi görür. Bu, zar oluşumunun nereye yönleneceğini belirler."},{"t":"ER katkısı","a":"Zar kaynağı","d":"Endoplazmik retikulum zar parçaları kromozom yüzeyine yönlenir ve burada birikir. ER zarları çekirdek zarının ham maddesini sağlar."},{"t":"Birleşme","a":"Zar tamamlanır","d":"ER parçaları kromozomlar çevresinde birleşerek çift katlı çekirdek zarını oluşturur. Çekirdek gözenekleri de bu sırada yerleşir."}],"ans":"Kromozom yüzeyi protein sinyalleri ER zar parçalarını çağırır; bunlar birleşerek çekirdek zarını oluşturur."},{"q":"Hayvan hücresinde sitokinezin kontraktil halkasının kasılması hangi protein etkileşimiyle gerçekleşir?","steps":[{"t":"Halka yapısı","a":"Aktin ve miyozin","d":"Kontraktil halka, aktin filamentleri ile miyozin motor proteinlerinden oluşur. Bu yapı hücre zarının iç yüzünde bulunur."},{"t":"Etkileşim","a":"Miyozin aktini çeker","d":"Miyozin proteinleri ATP enerjisiyle aktin filamentleri üzerinde kayar ve onları birbirine çeker. Bu, halkanın çapını küçültür."},{"t":"Sonuç","a":"Boğumlanma","d":"Halka daraldıkça hücre zarını içe doğru çeker ve bölünme oluğu derinleşir. Sonunda hücre ikiye boğumlanır."}],"ans":"Aktin-miyozin etkileşimiyle; miyozin ATP kullanarak aktini çeker ve halka daralır."},{"q":"Bitki hücresinde ara plağın (hücre plağı) Golgi kesecikleriyle oluşumu hangi aşamalardan geçer?","steps":[{"t":"Kesecik toplanması","a":"Ortaya yönlenir","d":"Golgi aygıtından kopan kesecikler, kalan iğ ipliklerinin yönlendirmesiyle hücrenin ekvator (orta) düzlemine toplanır. Bu keseciklere fragmoplast eşlik eder."},{"t":"Birleşme","a":"Plak oluşur","d":"Kesecikler birbiriyle birleşerek hücre plağını oluşturur. İçlerindeki polisakkaritler yeni çeper maddesini sağlar."},{"t":"Genişleme","a":"Çepere ulaşır","d":"Hücre plağı ortadan kenara doğru genişleyerek mevcut hücre çeperiyle birleşir. Böylece iki yeni hücre tam olarak ayrılır."}],"ans":"Golgi kesecikleri ortaya toplanır, birleşip hücre plağını oluşturur ve plak çepere doğru genişler."},{"q":"Telofazda CDK (siklin bağımlı kinaz) aktivitesinin düşmesi mitozdan çıkışı nasıl sağlar?","steps":[{"t":"CDK rolü","a":"Mitozu sürdürür","d":"Mitoz boyunca yüksek CDK-siklin aktivitesi, çekirdek zarının erimesi ve kromozom yoğunlaşması gibi olayları sürdürür. Bu aktivite hücreyi mitozda tutar."},{"t":"Siklin yıkımı","a":"CDK düşer","d":"Anafaz-telofaz geçişinde APC, mitotik siklinleri yıkım için işaretler. Siklin azalınca CDK aktivitesi düşer."},{"t":"Mitozdan çıkış","a":"Olaylar tersine döner","d":"CDK düşünce çekirdek zarı yeniden oluşur, kromozomlar gevşer ve iğ iplikleri dağılır. Böylece hücre mitozdan çıkıp telofazı tamamlar."}],"ans":"Siklin yıkımıyla CDK aktivitesi düşer; bu da çekirdek zarı oluşumu ve kromozom gevşemesini tetikleyerek mitozdan çıkışı sağlar."},{"q":"2n=46 kromozomlu bir insan hücresinde telofaz ve sitokinez sonunda oluşan her hücredeki kromozom ve DNA içeriği nasıldır?","steps":[{"t":"Anafaz sonu","a":"Her kutup 46 kromozom","d":"Anafazda kromatitler ayrılmış, her kutba 46 tek kromatitli kromozom gitmişti. Toplam DNA hâlâ 4C, her kutupta 2C'dir."},{"t":"Telofaz","a":"İki çekirdek","d":"Telofazda her kutupta 46 kromozomlu birer çekirdek oluşur. Kromozomlar kromatine dönüşür."},{"t":"Sitokinez sonu","a":"46 kromozom, 2C","d":"Sitokinezle iki hücre oluşur; her hücre 2n=46 kromozom ve 2C DNA içerir. Bu, G1 evresindeki ana hücreyle aynıdır."}],"ans":"Her hücre 2n=46 kromozom ve 2C DNA içerir; G1 evresindeki ana hücreyle aynıdır."},{"q":"Telofazda fragmoplast yapısının bitki hücresi sitokinezindeki işlevi nedir?","steps":[{"t":"Fragmoplast","a":"Mikrotübül yapısı","d":"Fragmoplast, telofazda iğ ipliği kalıntılarından oluşan mikrotübül ve aktin yapısıdır. Hücrenin ekvator bölgesinde bulunur."},{"t":"İşlev","a":"Kesecikleri yönlendirir","d":"Fragmoplast, Golgi keseciklerini hücrenin orta düzlemine yönlendirir ve taşır. Böylece hücre plağının doğru yerde oluşmasını sağlar."},{"t":"Sonuç","a":"Plak yönlendirilir","d":"Fragmoplast genişledikçe hücre plağı da kenara doğru büyütülür. Bu, ara plağın çepere ulaşmasını destekler."}],"ans":"Golgi keseciklerini orta düzleme yönlendirip hücre plağının doğru konumda oluşmasını sağlar."},{"q":"Telofazda çekirdek lamininin (lamin proteinleri) yeniden birleşmesi çekirdek zarının oluşumunu nasıl etkiler?","steps":[{"t":"Lamin görevi","a":"Zar iskeleti","d":"Lamin proteinleri çekirdek zarının iç yüzeyinde ağ benzeri bir iskelet oluşturur. Bu iskelet zara şekil ve dayanıklılık verir."},{"t":"Profazda durum","a":"Laminler ayrılmıştı","d":"Profazda laminler fosforlanarak ayrışmış ve çekirdek zarı parçalanmıştı. Bu, kromozomların serbest kalmasını sağlamıştı."},{"t":"Telofazda birleşme","a":"Zar yeniden kurulur","d":"Telofazda laminler defosforlanarak yeniden birleşir ve çekirdek iskeletini kurar. Bu, çekirdek zarının kromozomlar çevresinde yeniden oluşmasını sağlar."}],"ans":"Laminler yeniden birleşip çekirdek iskeletini kurarak çekirdek zarının yeniden oluşmasını sağlar."},{"q":"Telofazda iğ ipliklerinin parçalanmasıyla açığa çıkan tübülin alt birimlerinin hücredeki sonu nedir?","steps":[{"t":"Mikrotübül çözülmesi","a":"Tübülin serbest kalır","d":"Telofazda iğ iplikleri depolimerize olur ve tübülin alt birimleri serbest kalır. Bu alt birimler sitoplazmaya dağılır."},{"t":"Depolanma","a":"Havuza katılır","d":"Serbest tübülinler hücredeki tübülin havuzuna katılır. Burada gerektiğinde yeniden kullanılmak üzere bekler."},{"t":"Yeniden kullanım","a":"Yeni yapılar","d":"Bu tübülinler hücre iskeleti veya bir sonraki bölünmenin iğ iplikleri için yeniden kullanılır. Böylece hücre kaynak israf etmez."}],"ans":"Tübülin alt birimleri sitoplazmadaki havuza katılır ve yeni mikrotübül yapımında yeniden kullanılır."},{"q":"Telofazda sitokinez düzleminin (bölünme yerinin) anafazdaki iğ ipliklerinin konumuyla belirlenmesi neden önemlidir?","steps":[{"t":"Bölünme düzlemi","a":"İğ ipliği belirler","d":"Sitokinezin gerçekleşeceği düzlem, anafazdaki iğ ipliklerinin orta bölgesine göre belirlenir. Bölünme oluğu bu düzlemde oluşur."},{"t":"Önem","a":"Çekirdekleri ayırır","d":"Bölünme düzlemi tam iki çekirdek arasından geçmelidir. Aksi hâlde bir hücre iki çekirdek alır, diğeri hiç almaz."},{"t":"Sonuç","a":"Eşit dağılım","d":"Doğru konumlanan bölünme düzlemi, her yeni hücreye bir çekirdek düşmesini sağlar. Bu, eşit ve doğru bölünmenin garantisidir."}],"ans":"Bölünme düzlemi iki çekirdek arasından geçmeli; bu, her hücreye bir çekirdek düşmesini sağladığı için önemlidir."},{"q":"Telofaz ve sitokinez sonunda oluşan iki hücrenin organel sayısı bakımından durumu nasıldır?","steps":[{"t":"Organel paylaşımı","a":"Yaklaşık eşit","d":"Sitokinezde sitoplazmadaki mitokondri, kloroplast gibi organeller iki hücreye yaklaşık eşit dağılır. Bu dağılım rastgele ama dengelidir."},{"t":"Tam eşitlik yok","a":"Sayısal kesinlik olmaz","d":"Organel dağılımı kromozomlar gibi tam sayısal kesinlikte değildir. İki hücre tamamen eşit organel sayısı taşımayabilir."},{"t":"Telafi","a":"Çoğalarak dengelenir","d":"Organeller kendi başlarına bölünüp çoğalabildiği için sayı farkı zamanla dengelenir. Hücre büyürken organel sayısı normale döner."}],"ans":"Organeller yaklaşık eşit ama tam kesin olmayan biçimde dağılır; sonradan çoğalarak dengelenir."},{"q":"Telofaz sırasında kromozomların gevşeyip kromatine dönmesi sürecinde histon proteinleri nasıl rol oynar?","steps":[{"t":"Histon görevi","a":"DNA'yı paketler","d":"Histon proteinleri DNA'nın etrafına sarılarak onu paketleyen yapı taşlarıdır. Yoğunlaşma derecesini etkilerler."},{"t":"Bölünmede yoğunlaşma","a":"Sıkı paketlenme","d":"Bölünme sırasında histonların değişimiyle DNA çok sıkı paketlenip kromozom hâline gelmişti. Bu, taşımayı kolaylaştırmıştı."},{"t":"Telofazda gevşeme","a":"Paketlenme çözülür","d":"Telofazda histon değişiklikleri tersine döner ve DNA gevşek kromatin hâline gelir. Böylece genler erişilebilir hâle döner."}],"ans":"Histon değişiklikleri tersine dönerek DNA paketlenmesi gevşer ve kromozomlar kromatine döner."},{"q":"Telofazda hayvan hücresinde bölünme oluğunun derinleşmesi sırasında orta cisimcik (midbody) nasıl bir işlev görür?","steps":[{"t":"Bölünme oluğu","a":"Kontraktil halka daraltır","d":"Aktin-miyozin halkası hücreyi içe doğru sıkıştırarak bölünme oluğunu derinleştirir. İki hücre giderek birbirinden ayrılır."},{"t":"Orta cisimcik","a":"İnce köprü","d":"İki hücre tamamen ayrılmadan önce aralarında mikrotübüllerden oluşan ince bir köprü, yani orta cisimcik kalır. Bu köprü son bağlantıyı sağlar."},{"t":"Ayrılma","a":"Köprü kopar","d":"Son aşamada orta cisimcik kesilerek iki hücre tamamen ayrılır. Buna abscission (kesilme) denir."}],"ans":"Orta cisimcik, iki hücre arasındaki son mikrotübül köprüsüdür; kesilince hücreler tam ayrılır."},{"q":"Telofazda çekirdek zarı yeniden oluşurken çekirdek gözeneklerinin (por kompleksleri) yerleşmesi neden gereklidir?","steps":[{"t":"Çekirdek gözeneği","a":"Madde geçişi","d":"Çekirdek gözenekleri, çekirdek ile sitoplazma arasında madde alışverişini sağlayan kanallardır. RNA ve protein bu gözeneklerden geçer."},{"t":"Telofazda yerleşme","a":"Zara eklenir","d":"Telofazda çekirdek zarı oluşurken por kompleksleri de zar üzerine yerleşir. Bu, zarın işlevsel hâle gelmesini sağlar."},{"t":"Gereklilik","a":"İşlevsel çekirdek","d":"Gözenekler olmadan çekirdek madde alışverişi yapamaz ve gen ifadesi sürdürülemez. Bu yüzden gözenek yerleşimi işlevsel çekirdek için zorunludur."}],"ans":"Çekirdek-sitoplazma madde alışverişi için gözenekler şarttır; işlevsel çekirdek ancak böyle oluşur."},{"q":"Telofaz ve sitokinez tamamlandıktan sonra oluşan hücrelerin hücre döngüsünde girdiği evre hangisidir ve özelliği nedir?","steps":[{"t":"Bölünme sonu","a":"İki yeni hücre","d":"Telofaz ve sitokinez sonunda iki yeni hücre oluşur. Bu hücreler bölünmeyi tamamlamıştır."},{"t":"Girilen evre","a":"İnterfaz (G1)","d":"Yeni hücreler hücre döngüsünün interfaz evresine, özellikle G1 alt evresine girer. Burada hücre büyür ve metabolik olarak etkindir."},{"t":"Özellik","a":"Büyüme ve hazırlık","d":"G1 evresinde hücre boyut kazanır, organellerini çoğaltır ve protein üretir. Gerekirse bir sonraki bölünmeye hazırlanır."}],"ans":"İnterfazın G1 evresine girerler; bu evrede büyür, organel çoğaltır ve metabolik olarak etkin olurlar."},{"q":"Telofazda iki kardeş çekirdeğin genetik olarak özdeş olması, mitozun mayoz II telofazından ayrılan hangi özelliğiyle örtüşür?","steps":[{"t":"Mitoz telofaz","a":"Özdeş çekirdekler","d":"Mitoz telofazda oluşan iki çekirdek hem birbirinin hem de ana hücrenin aynısıdır. Çünkü kardeş kromatitler ayrılmıştır."},{"t":"Mayoz II telofaz","a":"Haploit ama farklı","d":"Mayoz II telofazda oluşan çekirdekler haploit (n) sayıdadır ve krossing-over nedeniyle birbirinden farklı olabilir. Sayı yarıya inmiştir."},{"t":"Örtüşen özellik","a":"Kardeş kromatit ayrımı","d":"Hem mitoz hem mayoz II'de kardeş kromatitler ayrılır. Ancak mitozda sonuç özdeş ve 2n iken, mayoz II'de n ve çeşitlidir."}],"ans":"Her ikisinde kardeş kromatitler ayrılır; ancak mitoz telofazı 2n özdeş hücre verirken mayoz II n ve genetik çeşitli hücre verir."}]}},"profazMayozI":{"ilkokul":{"kolay":[{"q":"Mayoz bölünme üreme hücreleri oluşurken görülür. Bu bölünmenin ilk evresine ne ad verilir ve bu evrede hücrenin durumu nasıldır?","steps":[{"t":"Mayozun başlangıcı","a":"İlk evre Profaz I","d":"Mayoz bölünme iki aşamada gerçekleşir: Mayoz I ve Mayoz II. İlk aşamanın başlangıç evresine Profaz I denir. Bu evrede hücre bölünmeye hazırlanır."},{"t":"Hücrenin durumu","a":"Kromozomlar belirginleşir","d":"Profaz I evresinde hücre içindeki kromozomlar kalınlaşıp kısalarak belirgin hale gelir. Böylece kromozomlar gözle ayırt edilebilecek duruma gelir."}],"ans":"Mayozun ilk evresi Profaz I evresidir; bu evrede kromozomlar belirginleşir."},{"q":"Profaz I evresinde benzer (homolog) kromozomlar yan yana gelir. Bu yan yana gelme olayına ne ad verilir?","steps":[{"t":"Benzer kromozomlar","a":"Homolog kromozomlar","d":"Vücudumuzdaki kromozomlar ikişerli takımlar halinde bulunur. Biri anneden, biri babadan gelen benzer kromozomlara homolog kromozom denir."},{"t":"Yan yana gelme","a":"Eşleşme yani sinapsis","d":"Profaz I evresinde homolog kromozomlar birbirine yaklaşıp yan yana dizilir. Bu yan yana gelme olayına eşleşme (sinapsis) denir."}],"ans":"Bu yan yana gelme olayına eşleşme (sinapsis) denir."},{"q":"Mayoz bölünme hangi tür hücrelerin oluşmasını sağlar ve niçin önemlidir?","steps":[{"t":"Oluşan hücreler","a":"Üreme hücreleri","d":"Mayoz bölünme sonucunda yumurta ve sperm gibi üreme hücreleri oluşur. Bu hücreler canlıların çoğalmasını sağlar."},{"t":"Önemi","a":"Neslin devamı","d":"Üreme hücreleri sayesinde canlılar yavru meydana getirir. Böylece canlı türlerinin devamı sağlanmış olur."}],"ans":"Mayoz bölünme üreme hücrelerini oluşturur ve neslin devamını sağlar."},{"q":"Profaz I evresinde yan yana gelen iki homolog kromozom toplam kaç kromatitten oluşan bir yapı meydana getirir?","steps":[{"t":"Bir kromozomun yapısı","a":"İki kromatit","d":"Bölünmeden önce her kromozom kendini eşler. Eşlenen her kromozom iki kardeş kromatitten oluşur."},{"t":"İki homologun birleşmesi","a":"Dört kromatit","d":"İki homolog kromozom yan yana geldiğinde her biri iki kromatit taşır. İkişer kromatitin toplanmasıyla dört kromatitli bir yapı oluşur."}],"ans":"Toplam dört kromatitten oluşan bir yapı meydana gelir."},{"q":"Mayoz bölünme vücudun hangi bölgelerinde gerçekleşir?","steps":[{"t":"Bölünmenin yeri","a":"Üreme organları","d":"Mayoz bölünme her hücrede değil, sadece üreme organlarında görülür. Erkekte testis, dişide yumurtalık bu görevi yapar."},{"t":"Sonuç","a":"Üreme hücresi üretimi","d":"Üreme organlarındaki özel hücreler mayoz geçirir. Böylece sperm ve yumurta hücreleri üretilmiş olur."}],"ans":"Mayoz bölünme üreme organlarında (testis ve yumurtalık) gerçekleşir."}],"zor":[{"q":"Profaz I evresinde yan yana gelen homolog kromozomlar birbirleriyle parça değiştirir. Bu olaya ne ad verilir ve canlıya ne kazandırır?","steps":[{"t":"Parça değişimi","a":"Krossing-over","d":"Profaz I evresinde yan yana gelen homolog kromozomlar belirli noktalardan birbirine değer. Bu noktalarda parça değiş tokuşu olur, buna krossing-over denir."},{"t":"Kazandırdığı özellik","a":"Çeşitlilik","d":"Parça değişimi sonucunda kromozomlardaki kalıtsal bilgiler yeniden düzenlenir. Bu durum canlılar arasında çeşitlilik (farklılık) oluşmasını sağlar."}],"ans":"Bu olaya krossing-over denir ve canlıya genetik çeşitlilik kazandırır."},{"q":"Mitozun profaz evresi ile mayozun profaz I evresi arasındaki en önemli fark nedir?","steps":[{"t":"Mitozun profazı","a":"Eşleşme yok","d":"Mitoz bölünmenin profaz evresinde homolog kromozomlar yan yana gelmez. Her kromozom tek başına hareket eder."},{"t":"Mayozun profaz I evresi","a":"Eşleşme ve parça değişimi var","d":"Mayozun profaz I evresinde ise homolog kromozomlar yan yana gelir ve parça değiştirir. Bu durum mitozda görülmez."}],"ans":"En önemli fark, profaz I evresinde homolog kromozomların eşleşip parça değiştirmesidir."},{"q":"Profaz I evresinde dört kromatitten oluşan yapıya tetrat denir. Bu yapı nasıl oluşur?","steps":[{"t":"Kromozomların eşlenmesi","a":"Her kromozom iki kromatit","d":"Bölünmeden önce her kromozom kendini eşler ve iki kardeş kromatitten oluşur. Bu kromatitler birbirine bağlı kalır."},{"t":"Homologların birleşmesi","a":"Tetrat oluşumu","d":"İki homolog kromozom yan yana geldiğinde her biri iki kromatit getirir. Toplam dört kromatitin bir araya gelmesiyle tetrat (dörtlü yapı) oluşur."}],"ans":"İki homolog kromozomun yan yana gelip dörtlü yapı oluşturmasıyla tetrat meydana gelir."},{"q":"Krossing-over olayı niçin tüm canlıların birbirinden farklı olmasına yardımcı olur?","steps":[{"t":"Bilgilerin karışması","a":"Anne ve baba parçaları","d":"Krossing-over sırasında anneden ve babadan gelen kromozom parçaları yer değiştirir. Böylece kalıtsal bilgiler yeni şekilde birleşir."},{"t":"Yeni kombinasyonlar","a":"Farklı üreme hücreleri","d":"Bu karışma sonucunda her üreme hücresi farklı bilgi taşır. Bu yüzden oluşan yavrular birbirinden farklı özellikler gösterir."}],"ans":"Krossing-over kalıtsal bilgileri yeniden karıştırdığı için canlılar arasında farklılık oluşur."},{"q":"Profaz I evresinde homolog kromozomların yan yana gelmesi (sinapsis) niçin gereklidir?","steps":[{"t":"Eşleşmenin amacı","a":"Parça değişimi için","d":"Homolog kromozomların yan yana gelmesi, aralarında parça değiştirebilmeleri için gereklidir. Yan yana gelmeden parça değişimi olamaz."},{"t":"Doğru ayrılma","a":"Düzenli dağılım","d":"Sinapsis ayrıca homolog kromozomların ileride doğru kutuplara ayrılmasını sağlar. Böylece üreme hücrelerine kromozomlar düzgün dağıtılır."}],"ans":"Sinapsis, parça değişiminin gerçekleşmesi ve kromozomların doğru ayrılması için gereklidir."}]},"ortaokul":{"kolay":[{"q":"Mayoz I bölünmesinin profaz I evresinde homolog kromozomlar arasında hangi olaylar gerçekleşir?","steps":[{"t":"Eşleşme","a":"Sinapsis gerçekleşir","d":"Profaz I evresinde anneden ve babadan gelen homolog kromozomlar birbirine yaklaşır. Yan yana dizilerek eşleşirler, bu olaya sinapsis denir."},{"t":"Tetrat oluşumu","a":"Dört kromatitli yapı","d":"Eşleşen iki homolog kromozomun her biri iki kromatit taşır. Bu sayede dört kromatitten oluşan tetrat adı verilen yapı meydana gelir."},{"t":"Parça değişimi","a":"Krossing-over","d":"Tetrat oluştuktan sonra homolog kromozomlar belirli noktalardan parça değiştirir. Krossing-over denilen bu olay genetik çeşitliliği artırır."}],"ans":"Profaz I evresinde sinapsis, tetrat oluşumu ve krossing-over gerçekleşir."},{"q":"Tetrat (bivalent) yapısı nedir ve kaç kromatitten oluşur?","steps":[{"t":"Tetratın tanımı","a":"Eşleşmiş homologlar","d":"Tetrat, profaz I evresinde yan yana gelen iki homolog kromozomun oluşturduğu yapıdır. Bu yapıya bivalent de denir."},{"t":"Kromatit sayısı","a":"Dört kromatit","d":"Her homolog kromozom iki kardeş kromatitten oluşur. İki homolog yan yana geldiğinde toplam dört kromatit bulunur."}],"ans":"Tetrat, iki homolog kromozomun eşleşmesiyle oluşan ve dört kromatit içeren yapıdır."},{"q":"Krossing-over olayı nedir ve hangi evrede gerçekleşir?","steps":[{"t":"Krossing-overin tanımı","a":"Parça değiş tokuşu","d":"Krossing-over, homolog kromozomların kromatitleri arasındaki parça değiş tokuşudur. Bu olay sırasında kalıtsal bilgi yeniden düzenlenir."},{"t":"Gerçekleştiği evre","a":"Profaz I","d":"Krossing-over, mayoz I bölünmesinin profaz I evresinde gerçekleşir. Çünkü homolog kromozomlar bu evrede yan yana gelir."}],"ans":"Krossing-over, homolog kromozomlar arasındaki parça değişimidir ve profaz I evresinde gerçekleşir."},{"q":"Sinapsis ne demektir ve mayozda hangi sonucu doğurur?","steps":[{"t":"Sinapsisin anlamı","a":"Homologların eşleşmesi","d":"Sinapsis, homolog kromozomların profaz I evresinde yan yana gelerek eşleşmesidir. Kromozomlar birbirine sıkıca yaklaşır."},{"t":"Sonucu","a":"Tetrat ve parça değişimi","d":"Sinapsis sayesinde tetrat yapısı oluşur. Bu yakınlaşma krossing-over olayının da gerçekleşmesini sağlar."}],"ans":"Sinapsis homolog kromozomların eşleşmesidir; tetrat oluşumunu ve krossing-overi sağlar."},{"q":"Profaz I evresi genetik çeşitliliğe nasıl katkıda bulunur?","steps":[{"t":"Parça değişimi","a":"Krossing-over etkisi","d":"Profaz I evresinde gerçekleşen krossing-over ile anne ve baba kromozom parçaları yer değiştirir. Böylece yeni gen birleşimleri oluşur."},{"t":"Çeşitlilik","a":"Farklı üreme hücreleri","d":"Bu yeniden düzenlenme sonucunda her üreme hücresi farklı kalıtsal bilgi taşır. Bu durum bireyler arası çeşitliliği artırır."}],"ans":"Profaz I evresindeki krossing-over yeni gen birleşimleri oluşturarak genetik çeşitliliğe katkı sağlar."}],"zor":[{"q":"Mitozun profaz evresi ile mayozun profaz I evresi karşılaştırıldığında ortaya çıkan iki temel fark nedir?","steps":[{"t":"Homolog eşleşmesi","a":"Sadece profaz I de var","d":"Mitozun profazında homolog kromozomlar yan yana gelmez ve eşleşmez. Mayozun profaz I evresinde ise homologlar eşleşerek tetrat oluşturur."},{"t":"Parça değişimi","a":"Sadece profaz I de var","d":"Mitozun profazında krossing-over görülmez, kromozomlar parça değiştirmez. Mayozun profaz I evresinde ise krossing-over ile parça değişimi olur."},{"t":"Sonuç","a":"Çeşitlilik farkı","d":"Bu iki olay mitozda olmadığı için oluşan hücreler özdeştir. Mayozda ise farklı kalıtsal bilgi taşıyan hücreler oluşur."}],"ans":"İki temel fark, profaz I evresinde homolog eşleşmesinin (sinapsis) ve parça değişiminin (krossing-over) görülmesidir."},{"q":"2n = 8 kromozomlu bir hücrede profaz I evresinde kaç tane tetrat oluşur?","steps":[{"t":"Homolog çift sayısı","a":"n = 4 çift","d":"Hücrede 2n = 8 kromozom bulunur, bu da 8 kromozomun 4 homolog çift halinde olduğu anlamına gelir. Yani n = 4 tür."},{"t":"Tetrat sayısı","a":"Çift sayısı kadar","d":"Her homolog çift bir tetrat oluşturur. 4 homolog çift olduğu için 4 tetrat meydana gelir."}],"ans":"2n = 8 kromozomlu hücrede profaz I evresinde 4 tetrat oluşur."},{"q":"Krossing-over sonucunda kardeş olmayan kromatitler arasında ne değişir ve bunun sonucu nedir?","steps":[{"t":"Değişen yapı","a":"Kromozom parçaları","d":"Krossing-over sırasında homolog kromozomların kardeş olmayan kromatitleri arasında parça değişimi olur. Yani gen taşıyan bölümler yer değiştirir."},{"t":"Genetik sonuç","a":"Yeni gen kombinasyonları","d":"Parça değişimi sonucunda kromatitler üzerinde anne ve baba genleri karışır. Böylece daha önce olmayan yeni gen birleşimleri ortaya çıkar."},{"t":"Bireysel sonuç","a":"Çeşitlilik artışı","d":"Bu yeni kombinasyonlar üreme hücrelerini birbirinden farklı kılar. Sonuçta bireyler arası genetik çeşitlilik artar."}],"ans":"Kardeş olmayan kromatitler arasında kromozom parçaları değişir, sonuçta yeni gen kombinasyonları ve genetik çeşitlilik oluşur."},{"q":"Profaz I evresinde homolog kromozomlar nasıl tanınır ve eşleşme neden bu evrede gerçekleşir?","steps":[{"t":"Homologların özelliği","a":"Aynı uzunluk ve gen","d":"Homolog kromozomlar aynı uzunlukta olup aynı özellikleri (genleri) kontrol eden bölgelere sahiptir. Biri anneden, biri babadan gelir."},{"t":"Eşleşmenin zamanı","a":"Profaz I başlangıcı","d":"Profaz I evresinde kromozomlar kalınlaşıp belirginleşir ve birbirini bulabilecek hale gelir. Bu nedenle eşleşme bu evrede gerçekleşir."},{"t":"Eşleşmenin amacı","a":"Tetrat ve parça değişimi","d":"Eşleşme tetrat yapısının oluşmasını sağlar ve parça değişimi için zemin hazırlar. Böylece krossing-over gerçekleşebilir."}],"ans":"Homologlar aynı uzunluk ve genleri sayesinde tanınır; eşleşme profaz I evresinde kromozomlar belirginleştiği için gerçekleşir."},{"q":"Profaz I evresinde krossing-over olmasaydı üreme hücrelerinin çeşitliliği nasıl etkilenirdi?","steps":[{"t":"Krossing-overin rolü","a":"Parça karıştırma","d":"Krossing-over, homolog kromozomlar arasında parça değiştirerek yeni gen birleşimleri oluşturur. Bu çeşitliliğin önemli kaynaklarından biridir."},{"t":"Olmaması durumu","a":"Daha az çeşitlilik","d":"Krossing-over olmasaydı kromozomlar anne ve babadan geldiği gibi kalırdı. Yeni gen birleşimleri oluşmaz, çeşitlilik azalırdı."}],"ans":"Krossing-over olmasaydı yeni gen birleşimleri oluşmaz ve üreme hücrelerinin çeşitliliği önemli ölçüde azalırdı."}]},"lise":{"kolay":[{"q":"Mayoz I bölünmesinin profaz I evresinde gerçekleşen sinapsis olayını ve sonucunu açıklayınız.","steps":[{"t":"Sinapsisin tanımı","a":"Homologların eşleşmesi","d":"Sinapsis, profaz I evresinde homolog kromozomların boyları boyunca yan yana gelip eşleşmesidir. Bu eşleşme sinaptonemal kompleks adı verilen protein yapısıyla desteklenir."},{"t":"Tetrat oluşumu","a":"Dört kromatitli yapı","d":"Eşleşen iki homolog kromozomun her biri iki kardeş kromatit içerir. Toplam dört kromatitli bu yapıya tetrat veya bivalent denir."},{"t":"Sonuç","a":"Parça değişimine hazırlık","d":"Sinapsis sayesinde homolog kromozomlar parça değiştirebilecek kadar yakınlaşır. Bu yakınlaşma krossing-over olayının temelini oluşturur."}],"ans":"Sinapsis, homolog kromozomların eşleşerek tetrat oluşturması olayıdır ve krossing-overe zemin hazırlar."},{"q":"Tetrat (bivalent) yapısının özelliklerini ve kaç kromatit içerdiğini açıklayınız.","steps":[{"t":"Tetratın oluşumu","a":"İki homolog eşleşir","d":"Tetrat, profaz I evresinde iki homolog kromozomun sinapsisle yan yana gelmesiyle oluşur. Bu yapı mayoza özgüdür."},{"t":"Kromatit sayısı","a":"Dört kromatit","d":"Her homolog kromozom interfazda eşlendiği için iki kardeş kromatit taşır. İki homolog yan yana geldiğinde toplam dört kromatit bulunur, bu nedenle tetrat denir."},{"t":"İşlevi","a":"Krossing-over yeri","d":"Tetrat yapısı, kardeş olmayan kromatitler arasında parça değişiminin gerçekleştiği yerdir. Bu sayede genetik çeşitlilik sağlanır."}],"ans":"Tetrat, iki homolog kromozomun eşleşmesiyle oluşan ve dört kromatit içeren, krossing-overin gerçekleştiği yapıdır."},{"q":"Krossing-over olayının profaz I evresinde nasıl gerçekleştiğini ve genetik sonucunu açıklayınız.","steps":[{"t":"Temas noktaları","a":"Kiyazma oluşumu","d":"Profaz I evresinde tetrat içindeki kardeş olmayan kromatitler kiyazma adı verilen noktalarda birbirine değer. Bu noktalar parça değişiminin yerleridir."},{"t":"Parça değişimi","a":"Gen alışverişi","d":"Kiyazma noktalarında kromatitler kırılarak parça değiştirir. Böylece homolog kromozomlar arasında gen alışverişi gerçekleşir."},{"t":"Genetik sonuç","a":"Yeni kombinasyonlar","d":"Parça değişimi sonucunda anne ve baba kaynaklı genler aynı kromatit üzerinde birleşir. Bu yeni gen kombinasyonları genetik çeşitliliği artırır."}],"ans":"Krossing-over, kiyazma noktalarında kardeş olmayan kromatitler arasında parça değişimidir ve yeni gen kombinasyonları oluşturur."},{"q":"Mitozun profaz evresi ile mayozun profaz I evresi arasındaki temel farkları açıklayınız.","steps":[{"t":"Homolog eşleşmesi","a":"Yalnızca mayozda","d":"Mitozun profazında homolog kromozomlar bağımsız hareket eder, eşleşmez. Mayozun profaz I evresinde ise homologlar sinapsisle eşleşip tetrat oluşturur."},{"t":"Krossing-over","a":"Yalnızca mayozda","d":"Mitozda krossing-over görülmez ve kromozomlar parça değiştirmez. Mayozun profaz I evresinde krossing-over ile parça değişimi gerçekleşir."},{"t":"Süre ve sonuç","a":"Daha uzun ve çeşitli","d":"Profaz I, mitoz profazına göre çok daha uzun sürer. Bu evredeki olaylar mayozda genetik çeşitlilik sağlarken mitozda özdeş hücreler oluşur."}],"ans":"Temel farklar, profaz I evresinde homolog eşleşmesinin ve krossing-overin görülmesi, ayrıca evrenin daha uzun sürmesidir."},{"q":"Sinaptonemal kompleks nedir ve profaz I evresindeki görevi nedir?","steps":[{"t":"Yapısı","a":"Protein iskeleti","d":"Sinaptonemal kompleks, eşleşen homolog kromozomlar arasında oluşan protein yapısıdır. Homologları boyları boyunca birbirine bağlar."},{"t":"Görevi","a":"Eşleşmeyi sabitler","d":"Bu kompleks homolog kromozomları yakın ve düzenli tutarak sinapsisi kararlı hale getirir. Böylece eşleşme bozulmadan devam eder."},{"t":"Önemi","a":"Krossing-over kolaylığı","d":"Sinaptonemal kompleks kromatitleri uygun konumda tuttuğu için parça değişimini kolaylaştırır. Bu sayede krossing-over doğru noktalarda gerçekleşir."}],"ans":"Sinaptonemal kompleks, homologları eşleşmiş tutan protein yapısıdır ve krossing-overi kolaylaştırır."},{"q":"Kiyazma nedir ve krossing-over ile ilişkisini açıklayınız.","steps":[{"t":"Kiyazmanın tanımı","a":"Çapraz temas noktası","d":"Kiyazma, profaz I evresinde tetrat içindeki kardeş olmayan kromatitlerin birbirine değdiği çapraz noktadır. Mikroskopta X şeklinde görülür."},{"t":"Krossing-over ile ilişkisi","a":"Parça değişimi yeri","d":"Kiyazma noktaları krossing-overin gerçekleştiği yerlerdir. Bu noktalarda kromatitler kırılıp parça değiştirir."}],"ans":"Kiyazma, kardeş olmayan kromatitlerin değdiği çapraz noktadır ve krossing-overin gerçekleştiği yerdir."},{"q":"Profaz I evresinin krossing-over yoluyla genetik çeşitliliğe katkısını açıklayınız.","steps":[{"t":"Gen karışımı","a":"Anne-baba genleri","d":"Krossing-over sırasında anne ve babadan gelen kromozom parçaları yer değiştirir. Bu sayede aynı kromatit üzerinde her iki kaynaktan genler bulunur."},{"t":"Yeni kombinasyonlar","a":"Rekombinant kromatitler","d":"Parça değişimi sonucu oluşan kromatitlere rekombinant denir. Bu kromatitler atalardan farklı gen dizilimi taşır."},{"t":"Çeşitliliğe etki","a":"Bireysel farklılık","d":"Rekombinant kromatitler farklı üreme hücreleri oluşturur. Böylece oluşan bireyler arasında genetik çeşitlilik artar."}],"ans":"Profaz I evresindeki krossing-over rekombinant kromatitler oluşturarak genetik çeşitliliği artırır."},{"q":"2n = 6 kromozomlu bir hücrede profaz I evresinde kaç tetrat oluşur ve bunlar kaç kromatit içerir?","steps":[{"t":"Homolog çift sayısı","a":"n = 3 çift","d":"Hücrede 2n = 6 kromozom bulunur, bu da 3 homolog çift demektir. Yani n = 3 tür."},{"t":"Tetrat sayısı","a":"3 tetrat","d":"Her homolog çift bir tetrat oluşturur. 3 homolog çift olduğundan profaz I evresinde 3 tetrat meydana gelir."},{"t":"Toplam kromatit","a":"12 kromatit","d":"Her tetrat dört kromatit içerir. 3 tetrat olduğu için toplam 3 x 4 = 12 kromatit bulunur."}],"ans":"2n = 6 kromozomlu hücrede 3 tetrat oluşur ve toplam 12 kromatit bulunur."},{"q":"Homolog kromozomlar nedir ve profaz I evresinde nasıl bir araya gelirler?","steps":[{"t":"Homologun tanımı","a":"Eş kromozomlar","d":"Homolog kromozomlar aynı uzunlukta, aynı sentromer konumuna ve aynı genleri taşıyan kromozom çiftleridir. Biri anneden, biri babadan gelir."},{"t":"Bir araya gelme","a":"Sinapsisle eşleşme","d":"Profaz I evresinde homolog kromozomlar boyları boyunca yan yana gelir ve eşleşir. Bu eşleşme olayına sinapsis denir."}],"ans":"Homolog kromozomlar aynı genleri taşıyan eş kromozomlardır ve profaz I evresinde sinapsisle eşleşirler."},{"q":"Profaz I evresinde çekirdek zarı ve çekirdekçik ile iğ ipliklerinde meydana gelen değişiklikleri açıklayınız.","steps":[{"t":"Çekirdek zarı","a":"Erimeye başlar","d":"Profaz I evresinin ilerleyen aşamalarında çekirdek zarı erimeye başlar. Böylece kromozomlar sitoplazma ile temas edebilir."},{"t":"Çekirdekçik","a":"Kaybolur","d":"Bu evrede çekirdekçik de yavaş yavaş kaybolur. Hücre bölünmeye uygun hale gelir."},{"t":"İğ iplikleri","a":"Oluşmaya başlar","d":"Sentrozomlar kutuplara çekilirken iğ iplikleri oluşmaya başlar. Bu iplikler kromozomları ileride taşıyacaktır."}],"ans":"Profaz I evresinde çekirdek zarı erir, çekirdekçik kaybolur ve iğ iplikleri oluşmaya başlar."},{"q":"Profaz I evresinde tetrat oluşumunun mayozun ilerleyen evreleri için önemini açıklayınız.","steps":[{"t":"Tetratın işlevi","a":"Homolog ayrımı için","d":"Tetrat yapısı homolog kromozomları bir arada tutar. Bu sayede homologlar metafaz I evresinde düzgün dizilebilir."},{"t":"Doğru ayrılma","a":"Anafaz I de ayrılır","d":"Tetrat içindeki homolog kromozomlar anafaz I evresinde zıt kutuplara çekilir. Tetrat oluşmazsa bu ayrılma düzenli olmaz."}],"ans":"Tetrat oluşumu, homolog kromozomların metafaz I ve anafaz I evrelerinde düzenli dizilip ayrılmasını sağlar."},{"q":"Profaz I evresinin mitoz profazına göre neden daha uzun ve karmaşık olduğunu açıklayınız.","steps":[{"t":"Ek olaylar","a":"Sinapsis ve krossing-over","d":"Profaz I evresinde mitozda olmayan sinapsis ve krossing-over olayları gerçekleşir. Bu ek işlemler ciddi zaman gerektirir."},{"t":"Yapısal düzenleme","a":"Tetrat ve kiyazma","d":"Homologların eşleşmesi, tetrat oluşumu ve kiyazma noktalarının düzenlenmesi karmaşık süreçlerdir. Bu yapısal düzenlemeler evreyi uzatır."}],"ans":"Profaz I evresi, sinapsis ve krossing-over gibi ek olaylar ile tetrat oluşumu içerdiği için mitoz profazından daha uzun ve karmaşıktır."},{"q":"Profaz I evresindeki krossing-over ile mitozda görülen kromozom davranışını karşılaştırınız.","steps":[{"t":"Mitozda kromozom","a":"Bağımsız davranır","d":"Mitozda her kromozom bağımsız hareket eder ve homologuyla etkileşmez. Parça değişimi olmaz, kromozomlar değişmeden kalır."},{"t":"Mayoz profaz I","a":"Parça değiştirir","d":"Mayozun profaz I evresinde homologlar eşleşip krossing-over ile parça değiştirir. Bu mitozda görülmeyen bir davranıştır."}],"ans":"Mitozda kromozomlar bağımsız ve değişmeden davranırken, profaz I evresinde homologlar eşleşip krossing-over ile parça değiştirir."},{"q":"Profaz I evresinde sentromerlerin durumu nasıldır ve kardeş kromatitler nasıl bağlıdır?","steps":[{"t":"Sentromerin durumu","a":"Bölünmemiştir","d":"Profaz I evresinde her kromozomun sentromeri tektir ve bölünmemiştir. Bu sentromer iki kardeş kromatidi bir arada tutar."},{"t":"Kardeş kromatitler","a":"Birlikte bağlı","d":"İki kardeş kromatit ortak sentromerle birbirine bağlıdır. Bu bağ mayoz I boyunca korunur, kromatitler ayrılmaz."}],"ans":"Profaz I evresinde sentromer bölünmemiştir ve kardeş kromatitler ortak sentromerle birbirine bağlı kalır."},{"q":"Profaz I evresinin alt aşamaları olduğu bilinir. Bu evrenin başlıca genel özelliklerini açıklayınız.","steps":[{"t":"Kromozom yoğunlaşması","a":"Belirginleşme","d":"Profaz I evresinin başında kromozomlar yoğunlaşarak kısalıp kalınlaşır. Böylece mikroskopta ayırt edilebilir hale gelir."},{"t":"Eşleşme","a":"Sinapsis","d":"Yoğunlaşan homolog kromozomlar yan yana gelerek eşleşir. Bu sırada tetrat yapıları oluşur."},{"t":"Parça değişimi","a":"Krossing-over","d":"Eşleşmenin ardından kardeş olmayan kromatitler arasında krossing-over gerçekleşir. Kiyazma noktaları belirginleşir."}],"ans":"Profaz I evresinde kromozomlar yoğunlaşır, homologlar sinapsisle eşleşip tetrat oluşturur ve krossing-over gerçekleşir."}],"zor":[{"q":"2n = 10 kromozomlu bir hücrede profaz I evresinde oluşan tetrat sayısını, toplam kromatit sayısını ve kromozom sayısını ayrı ayrı hesaplayınız.","steps":[{"t":"Homolog çift sayısı","a":"n = 5 çift","d":"Hücrede 2n = 10 kromozom bulunur, bu 5 homolog çift demektir. Yani n = 5 tür."},{"t":"Tetrat sayısı","a":"5 tetrat","d":"Her homolog çift bir tetrat oluşturur. 5 homolog çift olduğundan 5 tetrat meydana gelir."},{"t":"Kromatit ve kromozom","a":"20 kromatit, 10 kromozom","d":"Her tetrat dört kromatit içerir, 5 tetratta 5 x 4 = 20 kromatit bulunur. Sentromer sayısı kromozom sayısını verir, bu da 10 kromozomdur."}],"ans":"2n = 10 hücrede 5 tetrat, 20 kromatit ve 10 kromozom bulunur."},{"q":"Krossing-over olayının kardeş kromatitler arasında değil de kardeş olmayan kromatitler arasında gerçekleşmesinin genetik açıdan önemini açıklayınız.","steps":[{"t":"Kardeş kromatitler","a":"Genetik olarak özdeş","d":"Kardeş kromatitler aynı kromozomun eşlenmesiyle oluştuğu için genetik olarak özdeştir. Aralarında parça değişimi yeni bir bilgi oluşturmaz."},{"t":"Kardeş olmayan kromatitler","a":"Farklı kaynaklı","d":"Kardeş olmayan kromatitler farklı homologlardan, yani biri anneden biri babadan gelir. Bu kromatitler farklı alel kombinasyonları taşır."},{"t":"Genetik önem","a":"Yeni kombinasyon","d":"Krossing-over kardeş olmayan kromatitler arasında olduğu için anne ve baba alelleri yeniden düzenlenir. Bu rekombinasyon genetik çeşitliliğin kaynağıdır."}],"ans":"Krossing-over kardeş olmayan kromatitler arasında gerçekleştiği için farklı kaynaklı aleller yeniden düzenlenir ve yeni kombinasyonlar oluşur."},{"q":"Profaz I evresinde gerçekleşen krossing-over sayısının genetik çeşitlilik üzerindeki etkisini bir kromozom çiftinde birden fazla kiyazma olması durumuyla açıklayınız.","steps":[{"t":"Tek kiyazma","a":"Sınırlı değişim","d":"Bir tetratta tek kiyazma oluşursa sadece bir noktada parça değişimi olur. Bu durum sınırlı sayıda yeni kombinasyon yaratır."},{"t":"Çoklu kiyazma","a":"Daha fazla değişim","d":"Bir tetratta birden fazla kiyazma oluşursa farklı noktalarda parça değişimi gerçekleşir. Böylece kromatitler üzerinde daha karmaşık gen dizilimleri ortaya çıkar."},{"t":"Çeşitliliğe etki","a":"Artan kombinasyon","d":"Kiyazma sayısı arttıkça oluşabilecek rekombinant kromatit çeşidi de artar. Bu durum üreme hücrelerinin genetik çeşitliliğini yükseltir."}],"ans":"Kiyazma sayısı arttıkça parça değişim noktaları çoğalır, oluşabilecek rekombinant kromatit çeşidi ve genetik çeşitlilik artar."},{"q":"Profaz I evresindeki sinapsis ve krossing-over olaylarında hata oluşması (örneğin eşit olmayan krossing-over) durumunda ortaya çıkabilecek genetik sonuçları açıklayınız.","steps":[{"t":"Normal süreç","a":"Eşit parça değişimi","d":"Normal krossing-overde homolog kromozomlar eşit uzunlukta parça değiştirir. Böylece her kromatit gen sayısını korur."},{"t":"Eşit olmayan değişim","a":"Gen kazanımı veya kaybı","d":"Eşleşme hatalı olursa parça değişimi eşit olmayabilir. Bir kromatit fazla gen alırken diğeri gen kaybedebilir, bu duplikasyon veya delesyona yol açar."},{"t":"Sonuç","a":"Mutasyon","d":"Bu eşit olmayan değişimler kromozom yapısında bozukluk yani mutasyon oluşturur. Bazı kalıtsal hastalıkların kaynağı bu tür hatalardır."}],"ans":"Eşit olmayan krossing-over gen kazanımı veya kaybına (duplikasyon/delesyon) yol açarak kromozom mutasyonlarına ve kalıtsal hastalıklara neden olabilir."},{"q":"Bir canlının profaz I evresinde krossing-over hiç gerçekleşmeseydi, üreme hücrelerindeki çeşitliliğin yalnızca hangi mekanizmaya bağlı kalacağını açıklayınız.","steps":[{"t":"Krossing-overin katkısı","a":"Kromozom içi çeşitlilik","d":"Krossing-over kromozomların içindeki gen dizilimini değiştirerek çeşitlilik sağlar. Bu olmadığında kromozomlar bütün halinde kalır."},{"t":"Geriye kalan mekanizma","a":"Bağımsız dağılım","d":"Krossing-over olmasa bile homolog kromozomlar metafaz I evresinde rastgele dizilir ve anafaz I evresinde bağımsız dağılır. Bu bağımsız dağılım çeşitlilik sağlar."},{"t":"Sonuç","a":"Sınırlı çeşitlilik","d":"Bu durumda çeşitlilik yalnızca homolog kromozomların bağımsız dağılımına bağlı kalır. Toplam çeşitlilik krossing-overli duruma göre azalır."}],"ans":"Krossing-over olmasaydı çeşitlilik yalnızca homolog kromozomların bağımsız dağılımı mekanizmasına bağlı kalır ve azalırdı."},{"q":"Profaz I evresinde tetrat içindeki dört kromatidin diziliminin krossing-over olasılığına etkisini açıklayınız.","steps":[{"t":"Tetrat dizilimi","a":"Dört kromatit yakın","d":"Tetratta iki homolog kromozomun dört kromatidi sinaptonemal kompleks ile yakın tutulur. Bu yakınlık kromatitlerin birbirine değmesini kolaylaştırır."},{"t":"Temas ve kiyazma","a":"Çapraz noktalar","d":"Kromatitler yakın olduğunda kardeş olmayan kromatitler kiyazma noktalarında çaprazlaşır. Bu çapraz temaslar parça değişiminin gerçekleştiği yerlerdir."},{"t":"Olasılığa etki","a":"Artan krossing-over","d":"Dört kromatidin düzenli ve yakın dizilimi krossing-over olasılığını artırır. Düzensiz dizilimde parça değişimi azalır veya hatalı olur."}],"ans":"Tetrat içindeki dört kromatidin yakın ve düzenli dizilimi kiyazma oluşumunu kolaylaştırarak krossing-over olasılığını artırır."},{"q":"Profaz I evresinde oluşan rekombinant kromatitler ile rekombinant olmayan (parental) kromatitlerin farkını ve oluşumlarını açıklayınız.","steps":[{"t":"Parental kromatit","a":"Değişmemiş","d":"Parental kromatitler krossing-over geçirmemiş, atadan geldiği gen dizilimini koruyan kromatitlerdir. Üzerlerinde sadece tek kaynaklı genler bulunur."},{"t":"Rekombinant kromatit","a":"Parça değişmiş","d":"Rekombinant kromatitler krossing-over sonucu parça değiştirmiş kromatitlerdir. Üzerlerinde hem anne hem baba kaynaklı genler bulunur."},{"t":"Oluşum sonucu","a":"Karışık üreme hücreleri","d":"Bir tetratta hem parental hem rekombinant kromatitler oluşur. Bu kromatitler farklı üreme hücrelerine dağılarak çeşitlilik sağlar."}],"ans":"Parental kromatitler değişmemiş tek kaynaklı, rekombinant kromatitler ise krossing-over ile karışık gen taşıyan kromatitlerdir."},{"q":"Profaz I evresindeki olayların yumurta ve sperm oluşumundaki genetik çeşitliliğe nasıl temel oluşturduğunu açıklayınız.","steps":[{"t":"Krossing-overin etkisi","a":"Kromozom içi çeşitlilik","d":"Profaz I evresindeki krossing-over her kromozomda yeni gen dizilimleri oluşturur. Böylece tek bir kromozom bile birçok farklı gen kombinasyonu taşıyabilir."},{"t":"Hücre başına çeşitlilik","a":"Her gamet farklı","d":"Krossing-over ile oluşan rekombinant kromozomlar farklı yumurta ve sperm hücrelerine dağılır. Bu nedenle her gamet benzersiz olabilir."},{"t":"Tür düzeyinde etki","a":"Popülasyon çeşitliliği","d":"Bireyler benzersiz gametlerle döllendiğinde farklı yavrular oluşur. Bu durum tür içindeki genetik çeşitliliği ve uyum yeteneğini artırır."}],"ans":"Profaz I evresindeki krossing-over benzersiz gametler oluşturarak yumurta-sperm çeşitliliğinin ve tür içi genetik çeşitliliğin temelini oluşturur."},{"q":"Mitoz ve mayoz I profaz evreleri DNA miktarı, kromozom davranışı ve oluşacak hücreler açısından nasıl farklılaşır?","steps":[{"t":"DNA miktarı","a":"İkisinde de 2 kat","d":"Hem mitoz hem mayoz öncesi interfazda DNA eşlendiği için profaz evrelerinde DNA miktarı iki katına çıkmıştır. Bu açıdan benzerdirler."},{"t":"Kromozom davranışı","a":"Farklı","d":"Mitoz profazında kromozomlar bağımsız davranır. Mayoz profaz I evresinde ise homologlar eşleşir, tetrat oluşur ve krossing-over gerçekleşir."},{"t":"Oluşacak hücreler","a":"Özdeş veya çeşitli","d":"Mitoz, ana hücreyle özdeş hücreler oluşturur. Mayoz ise profaz I olayları sayesinde genetik çeşitlilik gösteren hücreler oluşturur."}],"ans":"DNA miktarı her ikisinde de iki kat olsa da, mayoz profaz I evresindeki homolog eşleşmesi ve krossing-over farklı, çeşitli hücreler oluşmasını sağlar."},{"q":"Profaz I evresinde sinaptonemal kompleksin doğru kurulamaması durumunda krossing-over ve sonraki evreler nasıl etkilenir?","steps":[{"t":"Sinaptonemal kompleksin rolü","a":"Homologları bağlar","d":"Sinaptonemal kompleks homolog kromozomları boyları boyunca düzgün eşleştirir. Bu eşleşme krossing-overin gerçekleşeceği konumu sağlar."},{"t":"Hatalı kurulum","a":"Krossing-over aksar","d":"Kompleks doğru kurulamazsa homologlar tam eşleşemez ve krossing-over gerçekleşmez ya da hatalı olur. Genetik çeşitlilik azalır."},{"t":"Sonraki evreler","a":"Hatalı ayrılma","d":"Eşleşme bozuk olduğunda homolog kromozomlar anafaz I evresinde düzgün ayrılamaz. Bu durum kromozom sayısı dengesiz gametlere (anöploidi) yol açabilir."}],"ans":"Sinaptonemal kompleks doğru kurulamazsa krossing-over aksar ve homologların hatalı ayrılmasıyla anöploid gametler oluşabilir."},{"q":"Profaz I evresinde homolog kromozomların eşleşmesi sırasında cinsiyet kromozomlarının (X ve Y) davranışını ve eşleşme bölgelerini açıklayınız.","steps":[{"t":"Cinsiyet kromozomları","a":"Kısmen homolog","d":"X ve Y kromozomları boyut ve gen içeriği açısından farklıdır, tam homolog değildir. Ancak uçlarında ortak genler taşıyan bölgeler bulunur."},{"t":"Eşleşme bölgesi","a":"Psödootozomal bölge","d":"X ve Y kromozomları yalnızca psödootozomal adı verilen ortak bölgelerinden eşleşir. Bu bölge eşleşme ve ayrılma için yeterlidir."},{"t":"Sonuç","a":"Doğru ayrılma","d":"Bu kısmi eşleşme sayesinde X ve Y kromozomları profaz I evresinde tutunur. Böylece anafaz I evresinde zıt kutuplara doğru ayrılabilir."}],"ans":"X ve Y kromozomları kısmen homologdur ve yalnızca psödootozomal bölgelerinden eşleşerek doğru ayrılmayı sağlar."},{"q":"Bir hücrede profaz I evresinde tetratlardaki krossing-over sayesinde oluşabilecek gamet çeşitliliğinin, sadece bağımsız dağılıma göre neden daha fazla olduğunu açıklayınız.","steps":[{"t":"Bağımsız dağılım","a":"Sınırlı kombinasyon","d":"Bağımsız dağılımda her homolog çift iki şekilde ayrılabilir, n çift için 2 üzeri n kombinasyon oluşur. Bu sayı sınırlıdır."},{"t":"Krossing-overin katkısı","a":"Sınırsız varyasyon","d":"Krossing-over kromozomların içindeki gen dizilimini de değiştirir. Her tetratta farklı noktalarda parça değişimi olabileceğinden olası kromatit çeşidi çok artar."},{"t":"Toplam etki","a":"Çok daha fazla çeşit","d":"Bağımsız dağılımdaki 2 üzeri n kombinasyona krossing-over varyasyonları eklenir. Böylece toplam gamet çeşitliliği bağımsız dağılımdan çok daha fazla olur."}],"ans":"Krossing-over kromozom içi gen dizilimini de değiştirdiği için, bağımsız dağılımın 2 üzeri n kombinasyonuna ek varyasyon katarak gamet çeşitliliğini çok artırır."},{"q":"Profaz I evresinin uzun sürmesinin krossing-overin doğruluğu açısından önemini açıklayınız.","steps":[{"t":"Uzun süre nedeni","a":"Karmaşık işlemler","d":"Profaz I evresinde homologların eşleşmesi, sinaptonemal kompleks kurulumu ve parça değişimi gibi karmaşık işlemler gerçekleşir. Bu işlemler zaman gerektirir."},{"t":"Doğruluk açısından","a":"Hizalama ve kontrol","d":"Uzun süre, homolog kromozomların doğru hizalanmasına ve parça değişiminin uygun noktalarda olmasına imkan verir. Aceleci bir süreç hatalı parça değişimine yol açabilir."}],"ans":"Profaz I evresinin uzun sürmesi, homologların doğru hizalanıp parça değişiminin uygun noktalarda gerçekleşmesini sağlayarak krossing-overin doğruluğunu artırır."},{"q":"Profaz I evresinde gerçekleşen krossing-over olmasaydı, bir bakteri gibi eşeysiz üreyen canlıların çeşitlilik durumuna benzer bir sonuç doğar mıydı? Açıklayınız.","steps":[{"t":"Eşeysiz üreme","a":"Düşük çeşitlilik","d":"Eşeysiz üreyen canlılar mitozla çoğalır ve yavrular ataya özdeştir. Bu nedenle çeşitlilik çok düşüktür, sadece mutasyonlarla sağlanır."},{"t":"Krossing-oversiz mayoz","a":"Hâlâ çeşitlilik var","d":"Krossing-over olmasa bile mayozda homolog kromozomların bağımsız dağılımı ve döllenmedeki rastgelelik çeşitlilik sağlar. Bu nedenle eşeysiz üremeyle tam aynı olmaz."},{"t":"Sonuç","a":"Kısmi azalma","d":"Krossing-over olmaması çeşitliliği azaltır ancak bağımsız dağılım ve döllenme varyasyonları devam eder. Bu yüzden eşeysiz üreme kadar düşük çeşitlilik oluşmaz."}],"ans":"Hayır, krossing-over olmasa bile bağımsız dağılım ve döllenme çeşitlilik sağladığından eşeysiz üreme kadar düşük bir çeşitlilik oluşmazdı."},{"q":"Profaz I evresinde homolog kromozomların eşleşememesi durumunda mayozun devamında oluşabilecek kromozom sayısı bozukluklarını açıklayınız.","steps":[{"t":"Eşleşmenin önemi","a":"Doğru ayrılma için","d":"Homolog kromozomların profaz I evresinde eşleşmesi, anafaz I evresinde doğru kutuplara ayrılmaları için gereklidir. Eşleşme bir nevi yönlendirme görevi görür."},{"t":"Eşleşememe durumu","a":"Ayrılmama (nondisjunction)","d":"Homologlar eşleşemezse anafaz I evresinde aynı kutba gidebilir, buna ayrılmama (nondisjunction) denir. Bir kutup fazla, diğeri eksik kromozom alır."},{"t":"Sonuç","a":"Anöploidi","d":"Ayrılmama sonucu oluşan gametlerde kromozom sayısı normalden fazla veya az olur, bu duruma anöploidi denir. Down sendromu gibi durumlar bu kökenlidir."}],"ans":"Homologlar eşleşemezse anafaz I evresinde ayrılmama (nondisjunction) görülür ve kromozom sayısı dengesiz, anöploid gametler oluşur."}]}},"metafazAnafazMayozI":{"ilkokul":{"kolay":[{"q":"Mayoz I bölünmesinde tetratlar hücrenin ortasında dizilir. Bu dizilmenin gerçekleştiği evrenin adı nedir?","steps":[{"t":"Ortada dizilme","a":"Ekvatorda toplanma","d":"Mayoz I sırasında tetratlar hücrenin tam ortasına, yani ekvator bölgesine gelir. Burada düzenli bir şekilde sıralanırlar."},{"t":"Evrenin adı","a":"Metafaz I","d":"Tetratların hücre ortasında dizildiği bu evreye metafaz I denir. Bu evre kromozomların ayrılmasından hemen öncedir."}],"ans":"Tetratların hücre ortasında dizildiği evre metafaz I evresidir."},{"q":"Anafaz I evresinde hücrenin iki ucuna doğru ne çekilir?","steps":[{"t":"Ayrılan yapılar","a":"Homolog kromozomlar","d":"Anafaz I evresinde yan yana duran homolog kromozomlar birbirinden ayrılır. Her biri hücrenin bir ucuna doğru çekilir."},{"t":"Çekilme yönü","a":"Zıt kutuplara","d":"Homolog kromozomlardan biri bir kutba, diğeri karşı kutba gider. Böylece kromozomlar iki gruba ayrılmış olur."}],"ans":"Anafaz I evresinde homolog kromozomlar hücrenin zıt kutuplarına çekilir."},{"q":"Mayoz I bölünmesi sonunda oluşan hücrelerin kromozom sayısı ana hücreye göre nasıl değişir?","steps":[{"t":"Ayrılma sonucu","a":"Kromozomlar paylaşılır","d":"Mayoz I sırasında homolog kromozomlar ayrılarak iki gruba bölünür. Her hücreye kromozomların yarısı düşer."},{"t":"Sayı değişimi","a":"Yarıya iner","d":"Bu paylaşma sonucunda oluşan hücrelerin kromozom sayısı ana hücrenin yarısı kadar olur. Kromozom sayısı azalır."}],"ans":"Mayoz I sonunda oluşan hücrelerin kromozom sayısı ana hücrenin yarısına iner."},{"q":"Mayoz I bölünmesinde sitoplazmanın bölünüp iki hücre oluştuğu evrenin adı nedir?","steps":[{"t":"Son evre","a":"Telofaz I","d":"Anafaz I evresinden sonra kromozomlar kutuplara ulaşır ve hücre ikiye bölünmeye başlar. Bu evreye telofaz I denir."},{"t":"Sonuç","a":"İki yeni hücre","d":"Telofaz I evresinde sitoplazma bölünerek iki yeni hücre oluşur. Bu hücreler mayoz II ye girecektir."}],"ans":"Sitoplazmanın bölünüp iki hücre oluştuğu evre telofaz I evresidir."},{"q":"Anafaz I evresinde homolog kromozomlar ayrılırken kardeş kromatitler birbirinden ayrılır mı?","steps":[{"t":"Kardeş kromatitler","a":"Birlikte kalır","d":"Anafaz I evresinde her kromozom hâlâ iki kardeş kromatit taşır. Bu kromatitler birbirine bağlı kalır, ayrılmaz."},{"t":"Ayrılan yapı","a":"Homologlar ayrılır","d":"Bu evrede sadece homolog kromozomlar birbirinden ayrılır. Kardeş kromatitlerin ayrılması mayoz II de gerçekleşir."}],"ans":"Hayır, anafaz I evresinde kardeş kromatitler birlikte kalır, sadece homolog kromozomlar ayrılır."}],"zor":[{"q":"Mayoz I bölünmesine niçin redüksiyon (azalma) bölünmesi denir?","steps":[{"t":"Kromozom ayrılması","a":"Homologlar ayrılır","d":"Mayoz I sırasında homolog kromozomlar birbirinden ayrılarak farklı hücrelere gider. Böylece her hücreye kromozomların sadece yarısı düşer."},{"t":"Sayının azalması","a":"2n den n ye","d":"Bu ayrılma sonucunda kromozom sayısı yarıya iner, yani 2n den n ye düşer. Sayı azaldığı için bu bölünmeye redüksiyon bölünmesi denir."}],"ans":"Mayoz I de kromozom sayısı yarıya indiği (2n den n ye) için ona redüksiyon (azalma) bölünmesi denir."},{"q":"Metafaz I evresinde tetratların ekvatorda çift sıra halinde dizilmesi, mitoz metafazından nasıl farklıdır?","steps":[{"t":"Mitoz metafazı","a":"Tek sıra","d":"Mitozun metafazında kromozomlar tek tek, ekvatorda tek sıra halinde dizilir. Her kromozom bağımsızdır."},{"t":"Mayoz metafaz I","a":"Çift sıra","d":"Mayoz I metafazında ise homolog kromozomlar tetrat halinde, ekvatorun iki yanına çift sıra dizilir. Bu tetratlardan kaynaklanır."}],"ans":"Mitoz metafazında kromozomlar tek sıra, mayoz metafaz I evresinde ise tetratlar çift sıra halinde dizilir."},{"q":"Anafaz I evresinde homolog kromozomların hangi kutba gideceğinin rastgele olması neye yol açar?","steps":[{"t":"Rastgele dağılım","a":"Bağımsız dağılım","d":"Anafaz I evresinde her homolog çift hangi kutba gideceği rastgele belirlenir. Bu duruma homolog kromozomların bağımsız dağılımı denir."},{"t":"Sonuç","a":"Çeşitlilik","d":"Bu rastgele dağılım sonucunda oluşan hücreler farklı kromozom karışımları taşır. Böylece üreme hücreleri arasında çeşitlilik oluşur."}],"ans":"Homolog kromozomların rastgele dağılımı, üreme hücreleri arasında genetik çeşitlilik oluşmasına yol açar."},{"q":"2n = 4 kromozomlu bir hücre mayoz I geçirdiğinde oluşan her bir hücrede kaç kromozom bulunur?","steps":[{"t":"Başlangıç sayısı","a":"4 kromozom","d":"Bölünmeye giren hücrede 2n = 4 kromozom bulunur. Bu kromozomlar 2 homolog çift halindedir."},{"t":"Yarıya inme","a":"2 kromozom","d":"Mayoz I de homolog kromozomlar ayrılarak sayı yarıya iner. Oluşan her hücreye n = 2 kromozom düşer."}],"ans":"2n = 4 kromozomlu hücre mayoz I geçirdiğinde her hücrede 2 kromozom bulunur."},{"q":"Mayoz I sonunda oluşan iki hücre birbiriyle tamamen aynı mıdır?","steps":[{"t":"Kromozom dağılımı","a":"Rastgele paylaşım","d":"Mayoz I sırasında homolog kromozomlar hücrelere rastgele dağılır. Her hücreye farklı homolog kromozom karışımı düşer."},{"t":"Sonuç","a":"Farklı hücreler","d":"Bu rastgele dağılım nedeniyle iki hücre aynı kromozom takımına sahip olmaz. Bu yüzden hücreler birbirinden farklıdır."}],"ans":"Hayır, homolog kromozomlar rastgele dağıldığı için mayoz I sonunda oluşan iki hücre birbirinden farklıdır."}]},"ortaokul":{"kolay":[{"q":"Mayoz I bölünmesinin metafaz I evresinde kromozomların nasıl dizildiğini açıklayınız.","steps":[{"t":"Tetratların hareketi","a":"Ekvatora gelir","d":"Metafaz I evresinde profaz I de oluşan tetratlar hücrenin ortasına, ekvator bölgesine gelir. İğ iplikleri kromozomlara tutunur."},{"t":"Dizilim şekli","a":"Çift sıra","d":"Tetratlar ekvatorda çift sıra halinde dizilir, yani her homolog çift karşılıklı durur. Bu dizilim mitozdan farklıdır."}],"ans":"Metafaz I evresinde tetratlar hücre ekvatorunda çift sıra halinde dizilir."},{"q":"Anafaz I evresinde hangi yapılar ayrılır ve nereye gider?","steps":[{"t":"Ayrılan yapı","a":"Homolog kromozomlar","d":"Anafaz I evresinde yan yana duran homolog kromozomlar birbirinden ayrılır. Kardeş kromatitler ayrılmaz, birlikte kalır."},{"t":"Gittikleri yer","a":"Zıt kutuplar","d":"Ayrılan homolog kromozomlar iğ iplikleriyle hücrenin zıt kutuplarına çekilir. Böylece her kutupta kromozomların yarısı toplanır."}],"ans":"Anafaz I evresinde homolog kromozomlar ayrılarak hücrenin zıt kutuplarına gider."},{"q":"Mayoz I bölünmesinde kromozom sayısının yarıya inmesi olayına ne ad verilir?","steps":[{"t":"Kromozom azalması","a":"Sayı yarıya iner","d":"Mayoz I de homolog kromozomlar ayrılınca her hücreye kromozomların yarısı düşer. Kromozom sayısı 2n den n ye iner."},{"t":"Olayın adı","a":"Redüksiyon","d":"Kromozom sayısının yarıya indiği bu olaya redüksiyon (azalma) denir. Bu yüzden mayoz I e redüksiyon bölünmesi de denir."}],"ans":"Kromozom sayısının yarıya inmesi olayına redüksiyon (azalma) denir."},{"q":"Telofaz I evresinde hücrede neler gerçekleşir?","steps":[{"t":"Kromozomların durumu","a":"Kutuplara ulaşır","d":"Telofaz I evresinde ayrılan homolog kromozomlar hücrenin kutuplarına ulaşır. Her kutupta n sayıda kromozom toplanır."},{"t":"Hücre bölünmesi","a":"Sitoplazma bölünür","d":"Bu evrede sitoplazma bölünerek iki yeni hücre oluşur. Bu hücreler haploid (n) kromozom sayısına sahiptir."}],"ans":"Telofaz I evresinde kromozomlar kutuplara ulaşır ve sitoplazma bölünerek iki haploid hücre oluşur."},{"q":"Homolog kromozomların bağımsız dağılımı nedir ve neye katkı sağlar?","steps":[{"t":"Bağımsız dağılım","a":"Rastgele ayrılma","d":"Anafaz I evresinde her homolog çiftin hangi kutba gideceği rastgeledir. Bir çiftin dağılımı diğerini etkilemez, buna bağımsız dağılım denir."},{"t":"Katkısı","a":"Genetik çeşitlilik","d":"Bağımsız dağılım sonucunda hücrelere farklı kromozom karışımları düşer. Bu durum genetik çeşitliliğe katkı sağlar."}],"ans":"Bağımsız dağılım, homolog kromozomların rastgele kutuplara ayrılmasıdır ve genetik çeşitliliğe katkı sağlar."}],"zor":[{"q":"Mitozun metafazı ile mayozun metafaz I evresi arasındaki temel fark nedir? Açıklayınız.","steps":[{"t":"Mitoz metafazı","a":"Tek sıra dizilim","d":"Mitozun metafazında kromozomlar tek tek ekvatorda tek sıra halinde dizilir. Her kromozom bağımsız davranır ve iki kutuptan iğ iplikleri bağlanır."},{"t":"Mayoz metafaz I","a":"Çift sıra dizilim","d":"Mayozun metafaz I evresinde homolog kromozomlar tetrat halinde, ekvatorun iki yanına çift sıra dizilir. Her tetrattan bir homolog tek kutuba bağlanır."},{"t":"Sonuç","a":"Farklı ayrılma","d":"Bu dizilim farkı nedeniyle mitozda kardeş kromatitler, mayoz I de ise homolog kromozomlar ayrılır. Sonuçta farklı hücreler oluşur."}],"ans":"Temel fark, mitoz metafazında tek sıra, mayoz metafaz I evresinde tetratların çift sıra dizilmesidir; bu da farklı ayrılmaya yol açar."},{"q":"Mayoz I bölünmesinde kromozom sayısının yarıya inmesi niçin gereklidir? Açıklayınız.","steps":[{"t":"Döllenme sorunu","a":"Sayı katlanması","d":"Üreme hücreleri döllenmede birleşir. Eğer kromozom sayısı yarıya inmeseydi, her döllenmede kromozom sayısı iki katına çıkardı."},{"t":"Redüksiyonun rolü","a":"n + n = 2n","d":"Mayoz I de sayı yarıya indiği için gametler n kromozom taşır. Döllenmede n + n birleşip 2n oluşur, böylece tür sayısı sabit kalır."},{"t":"Sonuç","a":"Kromozom sabitliği","d":"Bu sayede nesiller boyunca canlının kromozom sayısı değişmez. Tür kromozom sayısının korunması neslin sağlıklı devamı için gereklidir."}],"ans":"Kromozom sayısının yarıya inmesi gereklidir çünkü döllenmede sayı tekrar 2n olur ve böylece tür kromozom sayısı nesiller boyunca sabit kalır."},{"q":"2n = 6 kromozomlu bir hücrede anafaz I evresinde her kutba kaç kromozom gider ve bu kromozomlar kaç kromatit içerir?","steps":[{"t":"Homolog ayrılması","a":"Yarısı her kutba","d":"Hücrede 2n = 6 kromozom vardır, yani 3 homolog çift bulunur. Anafaz I de her homolog çiftten biri bir kutba gider."},{"t":"Kutuptaki kromozom","a":"3 kromozom","d":"Her kutba 3 homolog çiftten birer tane düşer, yani n = 3 kromozom gider. Böylece kromozom sayısı yarıya iner."},{"t":"Kromatit sayısı","a":"6 kromatit","d":"Anafaz I de kardeş kromatitler ayrılmadığı için her kromozom 2 kromatit taşır. 3 kromozom x 2 kromatit = 6 kromatit her kutupta bulunur."}],"ans":"Anafaz I evresinde her kutba 3 kromozom gider ve bunlar toplam 6 kromatit içerir."},{"q":"Homolog kromozomların bağımsız dağılımı 2n = 4 kromozomlu bir hücrede kaç farklı kromozom kombinasyonu oluşturabilir?","steps":[{"t":"Homolog çift sayısı","a":"n = 2 çift","d":"Hücrede 2n = 4 kromozom bulunur, bu da 2 homolog çift demektir. Yani n = 2 tür."},{"t":"Kombinasyon sayısı","a":"2 üzeri n","d":"Her homolog çift iki şekilde ayrılabilir. n çift için olası kombinasyon 2 üzeri n formülüyle bulunur."},{"t":"Hesaplama","a":"4 kombinasyon","d":"n = 2 olduğundan 2 üzeri 2 = 4 farklı kombinasyon oluşur. Yani bağımsız dağılım 4 çeşit gamet yapabilir."}],"ans":"2n = 4 kromozomlu hücrede bağımsız dağılım 2 üzeri 2 = 4 farklı kromozom kombinasyonu oluşturabilir."},{"q":"Anafaz I evresinde kardeş kromatitlerin ayrılmaması, mayozun amacı açısından neden önemlidir?","steps":[{"t":"Anafaz I deki ayrılma","a":"Sadece homologlar","d":"Anafaz I evresinde sadece homolog kromozomlar ayrılır, kardeş kromatitler sentromerle bağlı kalır. Böylece her kromozom hâlâ iki kromatit taşır."},{"t":"Mayoz II için gereklilik","a":"Kromatitler saklanır","d":"Kardeş kromatitlerin birlikte kalması, mayoz II de ayrılmaları için gereklidir. Eğer anafaz I de ayrılsalardı mayoz II için yapı kalmazdı."},{"t":"Sonuç","a":"İki aşamalı bölünme","d":"Bu sayede mayoz iki aşamada gerçekleşir, önce homologlar sonra kromatitler ayrılır. Bu düzen haploid gametlerin doğru oluşmasını sağlar."}],"ans":"Kardeş kromatitlerin anafaz I de ayrılmaması önemlidir çünkü onların mayoz II de ayrılması gerekir; bu iki aşamalı bölünme doğru haploid gametleri oluşturur."}]},"lise":{"kolay":[{"q":"Mayoz I bölünmesinin metafaz I evresinde tetratların dizilimini ve iğ ipliklerinin tutunmasını açıklayınız.","steps":[{"t":"Tetratların ekvatora gelişi","a":"Çift sıra dizilim","d":"Metafaz I evresinde tetratlar hücrenin ekvator bölgesine gelir. Homolog çiftler karşılıklı durarak çift sıra halinde dizilir."},{"t":"İğ ipliklerinin tutunması","a":"Tek kutuptan bağlanma","d":"Her homolog kromozomun kardeş kromatitlerine yalnızca bir kutuptan iğ iplikleri tutunur. Yani bir homolog bir kutuptan, diğer homolog karşı kutuptan çekilir."},{"t":"Dizilimin sonucu","a":"Ayrılmaya hazırlık","d":"Bu çift sıralı dizilim ve tek yönlü tutunma sayesinde homolog kromozomlar zıt kutuplara çekilmeye hazır hale gelir. Mitoz metafazından farklı bir düzendir."}],"ans":"Metafaz I evresinde tetratlar ekvatorda çift sıra dizilir ve her homologa tek kutuptan iğ iplikleri tutunarak ayrılmaya hazırlanır."},{"q":"Anafaz I evresinde gerçekleşen kromozom ayrılmasını ve kardeş kromatitlerin durumunu açıklayınız.","steps":[{"t":"Homologların ayrılması","a":"Zıt kutuplara","d":"Anafaz I evresinde iğ iplikleri kısalarak homolog kromozomları birbirinden ayırır. Her homolog kromozom zıt bir kutba doğru çekilir."},{"t":"Kardeş kromatitlerin durumu","a":"Birlikte kalır","d":"Bu evrede sentromer bölünmez, bu nedenle kardeş kromatitler ayrılmaz. Her kromozom iki kromatidiyle birlikte hareket eder."},{"t":"Sonuç","a":"Sayı yarıya iner","d":"Homolog kromozomların ayrılmasıyla her kutba kromozomların yarısı gider. Böylece kromozom sayısı 2n den n ye düşmeye başlar."}],"ans":"Anafaz I evresinde homolog kromozomlar zıt kutuplara ayrılır, kardeş kromatitler birlikte kalır ve kromozom sayısı yarıya iner."},{"q":"Mayoz I bölünmesine redüksiyon bölünmesi denmesinin nedenini açıklayınız.","steps":[{"t":"Homolog ayrılması","a":"Çiftler ayrılır","d":"Mayoz I de homolog kromozom çiftleri ayrılarak farklı hücrelere dağılır. Her hücreye her çiftten yalnızca bir kromozom düşer."},{"t":"Sayının azalması","a":"2n den n ye","d":"Bu ayrılma sonucu kromozom sayısı yarıya iner, yani diploit (2n) hücreden haploid (n) hücreler oluşur. Sayı azaldığı için redüksiyon denir."}],"ans":"Mayoz I de kromozom sayısı 2n den n ye düştüğü için bu bölünmeye redüksiyon (azalma) bölünmesi denir."},{"q":"Homolog kromozomların bağımsız dağılımının genetik çeşitliliğe katkısını açıklayınız.","steps":[{"t":"Bağımsız dağılım","a":"Rastgele yönelim","d":"Metafaz I evresinde her tetrat ekvatorda rastgele yönelir. Anafaz I de homologlar bu yönelime göre rastgele kutuplara dağılır."},{"t":"Olası kombinasyonlar","a":"2 üzeri n","d":"n homolog çift için 2 üzeri n farklı kromozom kombinasyonu oluşabilir. Her gamet bu kombinasyonlardan birini taşır."},{"t":"Çeşitliliğe katkı","a":"Farklı gametler","d":"Bu rastgele dağılım nedeniyle çok sayıda farklı gamet oluşur. Böylece bireyler arası genetik çeşitlilik artar."}],"ans":"Homolog kromozomların bağımsız dağılımı 2 üzeri n farklı kombinasyon oluşturarak genetik çeşitliliğe katkı sağlar."},{"q":"Telofaz I ve sitokinez evrelerinde gerçekleşen olayları açıklayınız.","steps":[{"t":"Kromozomların ulaşması","a":"Kutuplara varış","d":"Telofaz I evresinde ayrılan homolog kromozomlar hücrenin zıt kutuplarına ulaşır. Her kutupta n sayıda kromozom toplanır."},{"t":"Çekirdek oluşumu","a":"Yeni çekirdekler","d":"Bazı hücrelerde kutuplarda çekirdek zarı yeniden oluşabilir. Kromozomlar gevşeyebilir, ancak bu duruma göre değişir."},{"t":"Sitokinez","a":"İki haploid hücre","d":"Sitokinez ile sitoplazma bölünerek iki yeni hücre oluşur. Bu hücreler haploid (n) kromozom sayısına sahiptir ve mayoz II ye girecektir."}],"ans":"Telofaz I evresinde kromozomlar kutuplara ulaşır, çekirdekler yeniden oluşabilir ve sitokinezle iki haploid hücre meydana gelir."},{"q":"Mitozun metafazı ile mayozun metafaz I evresi arasındaki dizilim farkını açıklayınız.","steps":[{"t":"Mitoz metafazı","a":"Tek sıra","d":"Mitozun metafazında her kromozom ekvatorda tek tek, tek sıra halinde dizilir. Bağımsız kromozomların her birine her iki kutuptan iğ iplikleri tutunur."},{"t":"Mayoz metafaz I","a":"Çift sıra","d":"Mayozun metafaz I evresinde tetratlar ekvatorun iki yanına çift sıra halinde dizilir. Her homologa yalnızca bir kutuptan iğ iplikleri tutunur."}],"ans":"Mitoz metafazında kromozomlar tek sıra, mayoz metafaz I evresinde ise tetratlar çift sıra halinde dizilir."},{"q":"2n = 8 kromozomlu bir hücrede anafaz I evresinde her kutba giden kromozom ve kromatit sayısını hesaplayınız.","steps":[{"t":"Homolog çift sayısı","a":"4 çift","d":"Hücrede 2n = 8 kromozom bulunur, bu 4 homolog çift demektir. Anafaz I de her çiftten biri bir kutba gider."},{"t":"Kutuptaki kromozom","a":"4 kromozom","d":"Her kutba 4 homolog çiftten birer tane, yani n = 4 kromozom düşer. Böylece kromozom sayısı yarıya iner."},{"t":"Kromatit sayısı","a":"8 kromatit","d":"Anafaz I de kardeş kromatitler ayrılmadığından her kromozom 2 kromatit taşır. 4 kromozom x 2 = 8 kromatit her kutupta bulunur."}],"ans":"Anafaz I evresinde her kutba 4 kromozom ve toplam 8 kromatit gider."},{"q":"Mayoz I sonunda oluşan hücrelerin kromozom ve DNA durumunu ana hücreyle karşılaştırarak açıklayınız.","steps":[{"t":"Ana hücre","a":"2n, eşlenmiş DNA","d":"Mayoza giren ana hücre diploittir (2n) ve interfazda DNA eşlendiği için kromozomlar iki kromatitlidir. DNA miktarı iki katına çıkmıştır."},{"t":"Mayoz I sonu hücreler","a":"n, iki kromatitli","d":"Mayoz I sonunda homologlar ayrıldığı için hücreler haploittir (n). Ancak kardeş kromatitler hâlâ bağlı olduğundan her kromozom iki kromatit taşır."},{"t":"Karşılaştırma","a":"Sayı yarı, DNA yarı","d":"Kromozom sayısı 2n den n ye, DNA miktarı da yarıya inmiştir. Ancak DNA henüz mayoz II deki seviyeye göre fazladır çünkü kromatitler ikilidir."}],"ans":"Mayoz I sonunda kromozom sayısı 2n den n ye iner, DNA miktarı yarıya düşer ancak kromozomlar hâlâ iki kromatitlidir."},{"q":"Anafaz I evresinde sentromerin bölünmemesinin mayozun ilerleyişi açısından önemini açıklayınız.","steps":[{"t":"Sentromerin durumu","a":"Bölünmez","d":"Anafaz I evresinde sentromer bölünmez, kardeş kromatitler birbirine bağlı kalır. Bu mitoz anafazından önemli bir farktır."},{"t":"Mayoz II için önem","a":"Kromatitler saklanır","d":"Sentromerin bölünmemesi sayesinde kardeş kromatitler mayoz II ye kadar korunur. Mayoz II de sentromer bölünerek bu kromatitler ayrılır."}],"ans":"Anafaz I evresinde sentromer bölünmez; bu sayede kardeş kromatitler mayoz II de ayrılmak üzere korunur."},{"q":"Mayoz I bölünmesinde kromozom sayısının yarıya inmesinin döllenme açısından önemini açıklayınız.","steps":[{"t":"Gamet kromozom sayısı","a":"Haploid (n)","d":"Mayoz I sayesinde gametler haploid (n) kromozom sayısına sahip olur. Yani tür kromozom sayısının yarısını taşır."},{"t":"Döllenme","a":"n + n = 2n","d":"Döllenmede yumurta (n) ve sperm (n) birleşerek 2n kromozomlu zigot oluşturur. Böylece tür kromozom sayısı tekrar elde edilir."},{"t":"Sabit kalma","a":"Nesiller boyu denge","d":"Bu sayede kromozom sayısı nesiller boyunca sabit kalır. Eğer redüksiyon olmasaydı her döllenmede sayı katlanırdı."}],"ans":"Kromozom sayısının yarıya inmesi, döllenmede n + n birleşerek 2n oluşmasını sağlar ve tür kromozom sayısını nesiller boyunca sabit tutar."},{"q":"Metafaz I evresinde tetratların ekvatorda rastgele yönelmesinin gamet çeşitliliğine etkisini açıklayınız.","steps":[{"t":"Rastgele yönelim","a":"Bağımsız konumlanma","d":"Metafaz I evresinde her tetrat ekvatorda anneden ve babadan gelen kromozomların yönüne bakılmaksızın rastgele konumlanır. Bir tetratın yönü diğerini etkilemez."},{"t":"Dağılıma etki","a":"Farklı kombinasyon","d":"Bu rastgele yönelim anafaz I de homologların farklı kombinasyonlarda dağılmasını sağlar. n çift için 2 üzeri n kombinasyon oluşur."},{"t":"Gamet çeşitliliği","a":"Çok sayıda gamet","d":"Bu durum çok sayıda farklı gamet türü oluşmasına yol açar. Örneğin insanda 2 üzeri 23 farklı kombinasyon mümkündür."}],"ans":"Metafaz I evresinde tetratların rastgele yönelmesi 2 üzeri n farklı kombinasyon oluşturarak gamet çeşitliliğini büyük ölçüde artırır."},{"q":"Mitoz anafazı ile mayoz anafaz I evresinde ayrılan yapıların farkını açıklayınız.","steps":[{"t":"Mitoz anafazı","a":"Kardeş kromatitler ayrılır","d":"Mitozun anafazında sentromer bölünür ve kardeş kromatitler birbirinden ayrılarak zıt kutuplara gider. Her kutba kromozomun tek kromatidi düşer."},{"t":"Mayoz anafaz I","a":"Homologlar ayrılır","d":"Mayozun anafaz I evresinde ise homolog kromozomlar ayrılır, kardeş kromatitler birlikte kalır. Her kutba iki kromatitli kromozomlar gider."}],"ans":"Mitoz anafazında kardeş kromatitler, mayoz anafaz I evresinde ise homolog kromozomlar (kromatitler birlikte) ayrılır."},{"q":"Mayoz I bölünmesinin telofaz I sonunda oluşan iki hücrenin neden genetik olarak farklı olduğunu açıklayınız.","steps":[{"t":"Bağımsız dağılım","a":"Rastgele kromozom karışımı","d":"Anafaz I evresindeki bağımsız dağılım nedeniyle her hücreye farklı homolog kromozom karışımı düşer. Bu nedenle hücrelerin kromozom takımı aynı değildir."},{"t":"Krossing-over etkisi","a":"Rekombinant kromozomlar","d":"Profaz I de gerçekleşen krossing-over kromozomlar üzerinde gen dizilimini değiştirir. Bu rekombinant kromozomlar hücreler arası farkı artırır."},{"t":"Sonuç","a":"Farklı hücreler","d":"Hem bağımsız dağılım hem de krossing-over nedeniyle iki hücre farklı kalıtsal bilgi taşır. Bu yüzden genetik olarak özdeş değildir."}],"ans":"Bağımsız dağılım ve krossing-over nedeniyle iki hücreye farklı kromozom ve gen karışımları düşer, bu yüzden genetik olarak farklıdırlar."},{"q":"2n = 4 kromozomlu bir hücrede metafaz I evresinde tetratların kaç farklı şekilde dizilebileceğini ve sonucunu açıklayınız.","steps":[{"t":"Tetrat sayısı","a":"2 tetrat","d":"Hücrede 2n = 4 kromozom, yani 2 homolog çift bulunur. Metafaz I evresinde bu çiftler 2 tetrat oluşturur."},{"t":"Dizilim olasılığı","a":"2 üzeri n şekil","d":"Her tetrat ekvatorda iki farklı yönde dizilebilir. n = 2 tetrat için 2 üzeri 2 = 4 farklı dizilim mümkündür, ancak ayna görüntüleri sayılınca 2 temel dizilim oluşur."},{"t":"Sonuç","a":"Gamet çeşitliliği","d":"Bu farklı dizilimler anafaz I de homologların farklı dağılmasını sağlar. Böylece 4 farklı kromozom kombinasyonu taşıyan gametler oluşabilir."}],"ans":"2n = 4 hücrede 2 tetrat bulunur ve bunların dizilimi 2 üzeri 2 = 4 farklı kromozom kombinasyonu oluşturabilir."},{"q":"Mayoz I bölünmesinde homolog kromozomların ayrılmasının (anafaz I) genetik çeşitliliği nasıl sağladığını açıklayınız.","steps":[{"t":"Homolog dağılımı","a":"Rastgele ayrılma","d":"Anafaz I evresinde her homolog çiftten biri rastgele bir kutba gider. Anne ve baba kaynaklı kromozomlar farklı kombinasyonlarda dağılır."},{"t":"Kombinasyon oluşumu","a":"2 üzeri n çeşit","d":"Bu rastgele ayrılma sonucu n homolog çift için 2 üzeri n farklı kromozom kombinasyonu oluşur. Her gamet bu kombinasyonlardan birini taşır."}],"ans":"Anafaz I evresinde homologların rastgele ayrılması 2 üzeri n farklı kromozom kombinasyonu oluşturarak genetik çeşitlilik sağlar."}],"zor":[{"q":"İnsanda (2n = 46) yalnızca homolog kromozomların bağımsız dağılımı dikkate alındığında kaç farklı gamet oluşabileceğini hesaplayınız ve krossing-over eklendiğinde durumun nasıl değişeceğini açıklayınız.","steps":[{"t":"Homolog çift sayısı","a":"n = 23 çift","d":"İnsanda 2n = 46 kromozom bulunur, bu da 23 homolog çift demektir. Yani n = 23 tür."},{"t":"Bağımsız dağılım","a":"2 üzeri 23 gamet","d":"Her homolog çift bağımsız dağıldığı için 2 üzeri n formülü uygulanır. n = 23 olduğundan 2 üzeri 23 yani yaklaşık 8,4 milyon farklı gamet oluşabilir."},{"t":"Krossing-over etkisi","a":"Sınırsız varyasyon","d":"Krossing-over kromozomların içindeki gen dizilimini de değiştirir. Bu eklendiğinde olası gamet çeşidi 2 üzeri 23 sayısının çok üzerine çıkar, neredeyse sınırsız varyasyon oluşur."}],"ans":"Sadece bağımsız dağılımla 2 üzeri 23 (yaklaşık 8,4 milyon) gamet oluşur; krossing-over eklendiğinde varyasyon neredeyse sınırsız hale gelir."},{"q":"Anafaz I evresinde bir homolog çiftin ayrılmaması (nondisjunction) durumunda oluşacak gametlerin kromozom durumunu ve sonuçlarını açıklayınız.","steps":[{"t":"Normal ayrılma","a":"Her kutba bir homolog","d":"Normal anafaz I de her homolog çiftten biri bir kutba, diğeri karşı kutba gider. Böylece her gamet o çiftten bir kromozom alır."},{"t":"Ayrılmama durumu","a":"Her ikisi bir kutba","d":"Nondisjunctionda bir homolog çift ayrılmaz ve her ikisi aynı kutba gider. Bir kutup o kromozomdan iki tane alırken diğer kutup hiç almaz."},{"t":"Gamet ve sonuç","a":"n+1 ve n-1 gametler","d":"Sonuçta n+1 (fazla) ve n-1 (eksik) kromozomlu gametler oluşur. Bu gametler döllenirse trizomi (örneğin Down sendromu) veya monozomi gibi anöploidi durumları görülür."}],"ans":"Anafaz I de nondisjunction olursa n+1 ve n-1 kromozomlu gametler oluşur; bunlar döllenirse trizomi veya monozomi gibi anöploidi durumları ortaya çıkar."},{"q":"Mayoz I de redüksiyon gerçekleşmeseydi, yani homologlar ayrılmasaydı, döllenme ve sonraki nesillerde kromozom sayısı nasıl etkilenirdi?","steps":[{"t":"Redüksiyonun rolü","a":"Sayıyı yarıya indirme","d":"Mayoz I de homologların ayrılmasıyla kromozom sayısı 2n den n ye iner. Bu redüksiyon gametlerin haploid olmasını sağlar."},{"t":"Redüksiyon olmazsa","a":"Diploid gametler","d":"Homologlar ayrılmasaydı gametler 2n kromozomlu (diploid) olurdu. Bu durumda kromozom sayısı yarıya inmezdi."},{"t":"Döllenme sonucu","a":"Sayı katlanır","d":"Diploid gametler döllendiğinde 2n + 2n = 4n oluşurdu. Her nesilde kromozom sayısı katlanarak artar, bu da türün dengesini bozar ve canlılığı tehlikeye atar."}],"ans":"Redüksiyon olmazsa gametler 2n kalır, döllenmede 4n oluşur ve her nesilde kromozom sayısı katlanarak artarak türün dengesi bozulurdu."},{"q":"Metafaz I evresinde tetratların yönelimi ile mitozda kromozomların yönelimini karşılaştırarak, bu farkın oluşan hücrelerin genetik içeriğine etkisini açıklayınız.","steps":[{"t":"Mitozda yönelim","a":"Tek kromozom, tek sıra","d":"Mitoz metafazında her kromozom tek tek dizilir ve kardeş kromatitleri iki kutuptan çekilir. Yönelim genetik içeriği değiştirmez, kromozomlar özdeş dağılır."},{"t":"Mayozda yönelim","a":"Tetrat, rastgele yön","d":"Mayoz metafaz I de tetratlar rastgele yönelir ve her homolog tek kutuptan çekilir. Anne ve baba kromozomları rastgele kutuplara dağılır."},{"t":"Genetik içeriğe etki","a":"Özdeş veya çeşitli","d":"Mitozda yönelim önemli değildir, oluşan hücreler özdeştir. Mayozda rastgele yönelim farklı kromozom kombinasyonları oluşturur, bu yüzden hücreler genetik olarak çeşitlidir."}],"ans":"Mitozda yönelim hücreleri özdeş bırakırken, mayoz metafaz I evresinde tetratların rastgele yönelimi farklı kromozom kombinasyonları oluşturarak hücreleri genetik olarak çeşitlendirir."},{"q":"2n = 6 kromozomlu bir hücrede metafaz I, anafaz I ve telofaz I sonunda kromozom ve kromatit durumunu ayrıntılı olarak izleyiniz.","steps":[{"t":"Metafaz I","a":"3 tetrat, 12 kromatit","d":"Hücrede 2n = 6 kromozom, yani 3 homolog çift bulunur. Metafaz I evresinde 3 tetrat ekvatorda dizilir, her tetrat 4 kromatit içerdiği için toplam 12 kromatit vardır."},{"t":"Anafaz I","a":"Her kutba 3 kromozom","d":"Anafaz I evresinde homologlar ayrılır ve her kutba 3 kromozom (n = 3) gider. Kardeş kromatitler ayrılmadığı için her kutupta 3 x 2 = 6 kromatit bulunur."},{"t":"Telofaz I","a":"İki hücre, her birinde 3 kromozom","d":"Telofaz I sonunda sitoplazma bölünerek iki hücre oluşur. Her hücrede 3 kromozom (n) ve her kromozom iki kromatitli olduğundan 6 kromatit bulunur."}],"ans":"Metafaz I de 3 tetrat (12 kromatit), anafaz I de her kutba 3 kromozom (6 kromatit), telofaz I de her hücrede 3 kromozom ve 6 kromatit bulunur."},{"q":"Anafaz I evresinde homologların ayrılması ile mayoz II anafazındaki kardeş kromatitlerin ayrılmasının mayozun amacına nasıl birlikte hizmet ettiğini açıklayınız.","steps":[{"t":"Anafaz I ayrılması","a":"Sayıyı yarıya indirir","d":"Anafaz I de homolog kromozomlar ayrılarak kromozom sayısı 2n den n ye iner. Ancak hücreler hâlâ iki kromatitli kromozomlar taşır."},{"t":"Mayoz II anafazı","a":"Kromatitleri ayırır","d":"Mayoz II anafazında sentromer bölünür ve kardeş kromatitler ayrılır. Böylece her gamet tek kromatitli n kromozom taşır."},{"t":"Birlikte amaç","a":"Haploid gametler","d":"İki ayrılma birlikte gerçekleştiğinde önce homologlar sonra kromatitler ayrılır. Bu sayede DNA miktarı ve kromozom sayısı doğru oranda düşerek sağlıklı haploid gametler oluşur."}],"ans":"Anafaz I homologları ayırarak sayıyı yarıya indirir, mayoz II anafazı kromatitleri ayırarak DNA miktarını dengeler; ikisi birlikte sağlıklı haploid gametler oluşturur."},{"q":"Mayoz I bölünmesindeki bağımsız dağılım ile Mendel in bağımsız açılım ilkesi arasındaki ilişkiyi açıklayınız.","steps":[{"t":"Bağımsız dağılım","a":"Homologlar rastgele","d":"Mayoz I de farklı homolog çiftler birbirinden bağımsız olarak kutuplara dağılır. Bir çiftin dağılımı diğerini etkilemez."},{"t":"Mendel in ilkesi","a":"Genler bağımsız açılır","d":"Mendel in bağımsız açılım ilkesine göre farklı karakterlerin genleri gametlere bağımsız geçer. Bu ilke deneysel gözlemlere dayanır."},{"t":"İlişki","a":"Aynı olayın açıklaması","d":"Bağımsız dağılım, Mendel in bağımsız açılım ilkesinin hücresel temelidir. Farklı kromozomlarda bulunan genler, homologların bağımsız dağılımı sayesinde bağımsız kalıtılır."}],"ans":"Homolog kromozomların bağımsız dağılımı, farklı kromozomlardaki genlerin bağımsız kalıtılmasını sağlayarak Mendel in bağımsız açılım ilkesinin hücresel temelini oluşturur."},{"q":"Mayoz I sonunda DNA miktarının değişimini, ana hücreden başlayarak (2c referansıyla) ayrıntılı açıklayınız.","steps":[{"t":"İnterfaz sonu","a":"DNA 2 kat (4c)","d":"Mayoza giren diploid hücre normalde 2c DNA içerir. İnterfazda DNA eşlendiği için profaz I başında DNA miktarı iki katına, yani 4c ye çıkar."},{"t":"Mayoz I süreci","a":"Homologlar ayrılır","d":"Mayoz I de homolog kromozomlar ayrılır ancak kardeş kromatitler bağlı kalır. Bu nedenle her hücreye kromozomların ve DNA nın yarısı düşer."},{"t":"Mayoz I sonu","a":"DNA yarıya iner (2c)","d":"Mayoz I sonunda her hücrede DNA miktarı 4c den 2c ye iner. Ancak kromozomlar hâlâ iki kromatitli olduğundan haploid hücre için bu DNA fazladır, mayoz II de tekrar yarıya inecektir."}],"ans":"İnterfazda DNA 2c den 4c ye çıkar, mayoz I sonunda homologların ayrılmasıyla her hücrede 2c ye iner; ancak kromozomlar iki kromatitli olduğu için DNA mayoz II de tekrar yarıya inecektir."},{"q":"Bir hücrede anafaz I evresinde iğ ipliklerinin işlev görmemesi durumunda oluşacak sonucu ve hücrenin kromozom durumunu açıklayınız.","steps":[{"t":"İğ ipliklerinin görevi","a":"Homologları çeker","d":"Anafaz I evresinde iğ iplikleri kısalarak homolog kromozomları zıt kutuplara çeker. Bu çekme ayrılma için zorunludur."},{"t":"İşlev görmemesi","a":"Ayrılma olmaz","d":"İğ iplikleri işlev görmezse homolog kromozomlar ayrılamaz ve kutuplara gidemez. Tüm kromozomlar hücrenin merkezinde kalır."},{"t":"Sonuç","a":"Diploid hücre","d":"Bölünme tamamlanırsa kromozomların hepsi tek hücrede kalır, hücre haploid değil diploit (2n) olur. Bu durum dengesiz, anormal hücreler oluşturur."}],"ans":"İğ iplikleri işlev görmezse homologlar ayrılamaz, kromozomlar tek hücrede kalır ve beklenen haploid yerine diploit (2n) anormal hücre oluşur."},{"q":"Metafaz I ve anafaz I evrelerindeki olayların eşeyli üreyen canlılarda mitozla üreyen canlılara göre uyum (adaptasyon) avantajını açıklayınız.","steps":[{"t":"Mitozla üreme","a":"Özdeş bireyler","d":"Mitozla çoğalan canlılarda yavrular ataya özdeştir, çeşitlilik çok düşüktür. Bu canlılar çevre değişikliklerine sınırlı uyum gösterebilir."},{"t":"Metafaz I ve anafaz I etkisi","a":"Bağımsız dağılım","d":"Eşeyli üremede metafaz I deki rastgele yönelim ve anafaz I deki bağımsız dağılım farklı gametler oluşturur. Bu krossing-overle birleşince yüksek çeşitlilik sağlar."},{"t":"Uyum avantajı","a":"Değişime dayanıklılık","d":"Yüksek çeşitlilik sayesinde popülasyonda değişen koşullara uyabilen bireyler bulunma olasılığı artar. Böylece tür çevre değişikliklerine ve hastalıklara karşı daha dayanıklı olur."}],"ans":"Metafaz I ve anafaz I deki bağımsız dağılım yüksek genetik çeşitlilik sağlar; bu da popülasyonun çevre değişikliklerine uyum yeteneğini ve dayanıklılığını artırır."},{"q":"2n = 8 olan bir hücrede hem bağımsız dağılım hem de her tetratta bir krossing-over varsayıldığında gamet çeşitliliğinin neden yalnızca 2 üzeri 4 ten fazla olacağını açıklayınız.","steps":[{"t":"Bağımsız dağılım","a":"2 üzeri 4 kombinasyon","d":"Hücrede 2n = 8, yani n = 4 homolog çift bulunur. Sadece bağımsız dağılım dikkate alınırsa 2 üzeri 4 = 16 farklı kombinasyon oluşur."},{"t":"Krossing-overin katkısı","a":"Yeni kromatit çeşidi","d":"Her tetratta krossing-over kromozom içindeki gen dizilimini değiştirir. Bu, bağımsız dağılımdaki 16 kombinasyonun her birine ek varyasyon katar."},{"t":"Toplam etki","a":"16 dan çok fazla","d":"Krossing-over rekombinant kromozomlar oluşturduğu için her kromozom birçok farklı dizilimde olabilir. Bu nedenle toplam gamet çeşidi 2 üzeri 4 = 16 sayısından çok daha fazla olur."}],"ans":"Bağımsız dağılım 2 üzeri 4 = 16 kombinasyon verir, ancak krossing-over her kromozomda ek gen dizilimleri oluşturduğu için toplam gamet çeşidi 16 dan çok daha fazla olur."},{"q":"Mayoz I de homolog kromozomların ayrılması, kalıtsal hastalıkların (örneğin Down sendromu) oluşumuyla nasıl ilişkilendirilebilir? Açıklayınız.","steps":[{"t":"Normal ayrılma","a":"Dengeli gametler","d":"Normal mayoz I de homolog kromozomlar düzgün ayrılır ve her gamet her çiftten bir kromozom alır. Böylece gametler dengeli sayıda kromozom taşır."},{"t":"Ayrılmama (nondisjunction)","a":"21. çift ayrılmaz","d":"Eğer 21. kromozom çifti anafaz I de ayrılmazsa, bir gamette bu kromozomdan iki tane bulunur (n+1). Bu durum ayrılmama olarak adlandırılır."},{"t":"Sonuç","a":"Trizomi 21","d":"Bu n+1 gamet normal bir gametle döllenirse zigotta 21. kromozomdan üç tane olur (trizomi 21). Bu durum Down sendromuna neden olur."}],"ans":"Mayoz I de 21. kromozom çiftinin ayrılmaması (nondisjunction) n+1 gamet oluşturur; bu döllendiğinde trizomi 21 yani Down sendromu ortaya çıkar."},{"q":"Telofaz I sonunda bazı canlılarda interfaz görülmeden mayoz II ye geçilmesinin nedenini ve önemini açıklayınız.","steps":[{"t":"İnterfaz ve DNA eşlenmesi","a":"Normalde S evresi","d":"Normal bir hücre döngüsünde bölünmeler arasında interfaz vardır ve S evresinde DNA eşlenir. Bu eşlenme kromozomları iki kromatitli hale getirir."},{"t":"Mayoz I sonrası durum","a":"Kromatitler zaten ikili","d":"Mayoz I sonunda kardeş kromatitler ayrılmadığından kromozomlar hâlâ iki kromatitlidir. Yani mayoz II için yapı zaten hazırdır."},{"t":"Önemi","a":"DNA eşlenmesi gereksiz","d":"Bu nedenle mayoz I ile mayoz II arasında DNA eşlenmesi (S evresi) gerçekleşmez. Eğer DNA tekrar eşlenseydi gametlerde DNA miktarı yanlış olurdu, bu yüzden interfazsız geçiş gereklidir."}],"ans":"Mayoz I sonunda kromozomlar hâlâ iki kromatitli olduğu için DNA eşlenmesine gerek yoktur; bu nedenle interfazsız mayoz II ye geçilir, böylece gametlerin DNA miktarı doğru olur."},{"q":"Anafaz I evresindeki bağımsız dağılım ile profaz I deki krossing-over olaylarının genetik çeşitliliğe katkılarını karşılaştırınız.","steps":[{"t":"Krossing-over katkısı","a":"Kromozom içi varyasyon","d":"Profaz I deki krossing-over tek bir kromozomun içindeki gen dizilimini değiştirir. Anne ve baba genleri aynı kromozom üzerinde yeniden düzenlenir."},{"t":"Bağımsız dağılım katkısı","a":"Kromozomlar arası varyasyon","d":"Anafaz I deki bağımsız dağılım ise farklı homolog çiftlerin gametlere rastgele dağılmasını sağlar. Bu kromozomlar arası kombinasyon çeşitliliği oluşturur."},{"t":"Karşılaştırma","a":"Birbirini tamamlar","d":"Krossing-over kromozom içinde, bağımsız dağılım kromozomlar arasında çeşitlilik yaratır. İkisi birlikte çalışarak gamet çeşitliliğini katlanarak artırır."}],"ans":"Krossing-over kromozom içinde gen dizilimini değiştirirken bağımsız dağılım kromozomlar arasında kombinasyon oluşturur; ikisi birlikte genetik çeşitliliği büyük ölçüde artırır."},{"q":"Bir bitkide 2n = 12 ise mayoz I telofaz sonunda oluşan her hücrenin kromozom sayısını, kromatit sayısını ve DNA durumunu hesaplayıp açıklayınız.","steps":[{"t":"Başlangıç durumu","a":"2n = 12, eşlenmiş","d":"Bitki hücresinde 2n = 12 kromozom bulunur ve interfazda DNA eşlendiği için her kromozom iki kromatitlidir. Yani 6 homolog çift vardır."},{"t":"Telofaz I sonu kromozom","a":"n = 6 kromozom","d":"Mayoz I de homologlar ayrılarak kromozom sayısı yarıya iner. Her hücreye n = 6 kromozom düşer."},{"t":"Kromatit ve DNA","a":"12 kromatit, DNA fazla","d":"Kardeş kromatitler ayrılmadığından her kromozom iki kromatit taşır, yani 6 x 2 = 12 kromatit bulunur. DNA miktarı yarıya inmiştir ancak kromatitler ikili olduğu için mayoz II de tekrar azalacaktır."}],"ans":"2n = 12 bitkide mayoz I telofaz sonunda her hücrede 6 kromozom, 12 kromatit bulunur ve DNA miktarı yarıya inmiştir, ancak kromozomlar iki kromatitli olduğu için DNA mayoz II de tekrar azalacaktır."}]}}};
